if (Requesting("action")=="recibir_traspaso"){ 
	
	$id_traspaso = Requesting("id_traspaso");  
	
	$resultStatus 	= "ok"; 
	$resultText 	= "Correcto.";	 
	$nombre = "";
	
	$continua = 1;
	
	$query = "SELECT id_salida, id_sucursal_origen, id_sucursal_destino, aceptado FROM traspaso_inventario WHERE id_traspaso = ".$id_traspaso;
	$id_salida 				= GetValueSQL($query,"id_salida");
	$id_sucursal_origen 	= GetValueSQL($query,"id_sucursal_origen");
	$id_sucursal_destino 	= GetValueSQL($query,"id_sucursal_destino");
	$aceptado 				= GetValueSQL($query,"aceptado");
	
	if($aceptado == 0){
		
		$querycs = "SELECT codigo FROM salida_almacen_rapida WHERE id_salida = ".$id_salida;
		$codigo_salida = GetValueSQL($querycs,"codigo");
		
		$query2 = "SELECT id_inventario, cantidad FROM salida_almacen_rapida_inv WHERE id_salida = ".$id_salida;
		$qresult = DatasetSQL($query2);
		while ($row = mysqli_fetch_array($qresult)){
			/* guardamos en el inventario nuevo, generamos moviemiento*/
			$query3 = "SELECT codigo_2, id_producto, id_fabricante, lote, fecha_cad FROM inventario WHERE id_inventario = ".$row['id_inventario'];
			$codigo_2 		= GetValueSQL($query3,"codigo_2");
			$id_producto 	= GetValueSQL($query3,"id_producto");
			$id_fabricante 	= GetValueSQL($query3,"id_fabricante");
			$lote 			= GetValueSQL($query3,"lote");
			$caducidad 		= GetValueSQL($query3,"fecha_cad"); 
			
			$query4 = "SELECT COUNT(id_inventario) AS existe, id_inventario, cantidad FROM inventario WHERE codigo_2 = '".$codigo_2."' AND id_almacen = ".$id_sucursal_destino;
			$existe = GetValueSQL($query4,"existe");
			if($existe > 0){
				$id_inventario 		= GetValueSQL($query4,"id_inventario"); 
				$cantidad_actual 	= GetValueSQL($query4,"cantidad"); 
				$cantidad_nueva 	= ($cantidad_actual) + ($row['cantidad']);
				if($cantidad_nueva < 0){ $cantidad_nueva = 0; }
							
				$query5 = "UPDATE inventario SET cantidad = ".$cantidad_nueva.", kardex = NOW(), id_usuario_kardex = ".$_SESSION['id_sesion']." WHERE id_inventario = ".$id_inventario;
				ExecuteSQL($query5); 
				
				//	$query_mov = "INSERT INTO movimiento_almacen (id_inventario, tipo, cantidad_antes, cantidad_manipulada, cantidad_despues, comentarios, kardex, id_usuario_kardex) 
				//		VALUES (".$id_inventario.", 1, ".$row['cantidad'].", 'Traspaso / Salida : ".$codigo_salida."', NOW(), ".$_SESSION['id_sesion'].")";  
				//	ExecuteSQL($query_mov);  
				
				$query_invd = "SELECT cantidad FROM inventario WHERE id_inventario = ".$id_inventario;
				$cantidad_despues = GetValueSQL($query_invd,"cantidad");
				$comentarios_movimiento_almacen = "RECIBO TRASPASO ".$codigo_salida;
				registra_movimiento_almacen($id_inventario, 1, $cantidad_actual, $row['cantidad'], $cantidad_despues, $comentarios_movimiento_almacen);
							
							
			}else{			
				$query_an 	= "SELECT COUNT(id_area) As existe, id_area FROM area WHERE id_almacen = ".$id_sucursal_destino." ORDER BY id_area DESC";
				$existe_area = GetValueSQL($query_an,"existe");  
				if($existe_area > 0){
					$id_area = GetValueSQL($query_an,"id_area");  
	
					$query_san 	= "SELECT COUNT(subarea.id_subarea) AS existe, subarea.id_subarea FROM subarea 
									INNER JOIN area ON (area.id_area = subarea.id_area) 
									WHERE area.id_almacen = ".$id_sucursal_destino." ORDER BY id_subarea DESC"; 
					$existe_subarea = GetValueSQL($query_san,"existe");  
					if($existe_subarea > 0){
					
						$id_subarea = GetValueSQL($query_san,"id_subarea");  
						$nivel = "1A1";  
					
						$query5 = "INSERT INTO inventario (id_producto, id_fabricante, codigo_2, lote, fecha_cad, id_almacen, 
									id_area, id_subarea, nivel, cantidad, kardex, id_usuario_kardex)
									VALUES (".$id_producto.", ".$id_fabricante.", '".$codigo_2."', '".$lote."', '".$caducidad."', ".$id_sucursal_destino.", 
									".$id_area.", ".$id_subarea.", '".$nivel."', ".$row['cantidad'].", NOW(), ".$_SESSION['id_sesion'].")";
						$id_inventario = ExecuteSQL_returnID($query5);   
						
						//	$query_mov = "INSERT INTO movimiento_almacen (id_inventario, tipo, cantidad, comentarios, kardex, id_usuario_kardex) VALUES 
						//					(".$id_inventario.", 1, ".$row['cantidad'].", 'Traspaso / Salida : ".$codigo_salida."', NOW(), ".$_SESSION['id_sesion'].")";  
						//	ExecuteSQL($query_mov);
						
						$query_invd = "SELECT cantidad FROM inventario WHERE id_inventario = ".$id_inventario;
						$cantidad_despues = GetValueSQL($query_invd,"cantidad");
						$comentarios_movimiento_almacen = "Recibo traspaso ".$codigo_salida;
						registra_movimiento_almacen($id_inventario, 1, 0, $row['cantidad'], $cantidad_despues, $comentarios_movimiento_almacen);
				
					}else{
						$continua = 0;
						$resultStatus 	= "Error";  
						$resultText 	= "Por favor registre una SUBÁREA en Catálogos.";	 
					}
				}else{
					$continua = 0;
					$resultStatus 	= "Error"; 
					$resultText 	= "Por favor registre un ÁREA en Catálogos.";	 
				}
				
				
			}
		}	
		
		
		/*update de fecha de recibido*/
		if($continua == 1){
			$query_f = "UPDATE traspaso_inventario SET 
					fecha_recibido = NOW(), 
					aceptado = 1 ,
					kardex = NOW(),
					id_usuario_kardex = ".$_SESSION['id_sesion']."
				WHERE id_traspaso = ".$id_traspaso;
			ExecuteSQL($query_f); 
		}
	 
	}else{
		$resultStatus 	= "error"; 
		$resultText 	= "Traspaso ya recibido.";	 
	}
	
	

	$result = array(  
		'result' 		=> $resultStatus, 
		'result_text' 	=> $resultText
	);		 
	XML_Envelope($result);  
	exit;		 
} 
 
