if (Requesting("action")=="cambiar_sucursal_version_uno"){ 
//if (Requesting("action")=="cambiar_sucursal"){ 
	
	$id_sucursal = Requesting("id_sucursal"); 
	
	$resultStatus 	= "ok"; 
	$resultText 	= "Correcto. Sucursal actualizada de forma exitosa.";	 
	$nombre = "";
	
	$query_tu = "SELECT tipo_usuario FROM tipo_usuario WHERE id_tipo_usuario = ".$_SESSION['id_tipo_usuario'];
	$tipo_de_usuario = GetValueSQL($query_tu,"tipo_usuario");
	if($tipo_de_usuario === $tipo_usuario_sistemas OR $tipo_de_usuario === $tipo_usuario_administrador){
			
		$query = "SELECT COUNT(id_almacen) AS existe, nombre FROM almacen WHERE id_almacen = ".$id_sucursal;
		$existe = GetValueSQL($query,"existe");
		
		if($existe > 0){
			$nombre = GetValueSQL($query,"nombre");
			$_SESSION['id_almacen'] = $id_sucursal;
		}else{
			$resultStatus 	= "error";
			$resultText 	= "Lo sentimos, ocurrio un error. Intenta de nuevo.";	 
		}	
	}else if($tipo_de_usuario === $tipo_usuario_vendedor 
				OR $tipo_de_usuario === $tipo_usuario_tecnico 
				OR $tipo_de_usuario === $tipo_usuario_gerente){
			
		$queryx = "SELECT COUNT(id_sucursal) AS existe, id_sucursal FROM usuario_sucursal WHERE id_usuario = ".$_SESSION['id_sesion']." AND id_sucursal = ".$id_sucursal;
		$existe = GetValueSQL($queryx,"existe");
		
		if($existe > 0){
			
			$query = "SELECT nombre FROM almacen WHERE id_almacen = ".$id_sucursal;					
			$nombre = GetValueSQL($query,"nombre");
			$_SESSION['id_almacen'] = $id_sucursal;
		}else{
			
			$queryyx2 = "SELECT COUNT(id_usuario) AS existe FROM usuario WHERE id_usuario = ".$_SESSION['id_sesion']." AND id_almacen = ".$id_sucursal;
			
			//echo $queryyx2;
			$existeyx2 = GetValueSQL($queryyx2,"existe");
			
			if($existeyx2 > 0){
				$query = "SELECT nombre FROM almacen WHERE id_almacen = ".$id_sucursal;					
				$nombre = GetValueSQL($query,"nombre");
				$_SESSION['id_almacen'] = $id_sucursal;
			}else{
				$resultStatus 	= "error";
				$resultText 	= "Lo sentimos, ocurrio un error. Intenta de nuevo.";	 
			}
			
		}	
	}else{
		$resultStatus 	= "error";
		$resultText 	= "No tiene permisos para cambiar sucursal.";	 
	}		

	$result = array(  
		'nombre' 		=> $nombre, 
		'usuario' 		=> $_SESSION['usuario'] , 
		'id_sucursal' 	=> $id_sucursal,  
		'result' 		=> $resultStatus, 
		'result_text' 	=> $resultText
	);		 
	XML_Envelope($result);  
	exit;		 
} 

