				FROM menu 				
				ORDER BY orden";
			$qresult = DatasetSQL($query);
			while ($row = mysqli_fetch_array($qresult)){
				/* busca permiso de usuario para el menu*/
				$query_pm = "SELECT COUNT(id_permiso_menu) AS existe 
					FROM permiso_menu 
					WHERE id_almacen = ".$_SESSION['id_almacen']." AND id_menu = ".$row['id_menu']." AND id_tipo_usuario IN (".$permisos_usuario.")";
				$existe_permiso_menu = GetValueSQL($query_pm,"existe");			
				if($existe_permiso_menu > 0){
					if($row["tiene_sub"] == 1){
