							$existe_permiso_submenu = GetValueSQL($query_psm,"existe");			
							if($existe_permiso_submenu > 0){							
								if($row2["tiene_sub"] == 1){								
									$sub_menu .= '<li> <a href="'.$row2["href"].'"><i class="bx bx-right-arrow-alt"></i>'.$row2["menusub"].'</a>';								
									$hasarrow = "has-arrow";					
									$sub_menu .= "<ul>";
									/*busca el subsubmenu*/ 								
									$query3 = "SELECT id_menusubsub, menusubsub, orden, href FROM menusubsub WHERE id_menusub = ".$row2['id_menusub']." ORDER BY orden";
									$qresult3 = DatasetSQL($query3);
									while ($row3 = mysqli_fetch_array($qresult3)){ 	
										/* busca permiso de usuario para el submenu*/
										$query_pssm = "SELECT COUNT(id_permiso) AS existe 
											FROM permiso_subsubmenu 
											WHERE id_almacen = ".$_SESSION['id_almacen']." AND id_subsubmenu = ".$row3['id_menusubsub']." AND id_tipo_usuario IN (".$permisos_usuario.")";
										$existe_permiso_subsubmenu = GetValueSQL($query_pssm,"existe");			
										if($existe_permiso_subsubmenu > 0){						 
											$sub_menu .= '<li> <a href="'.$row3["href"].'"><i class="bx bx-right-arrow-alt"></i>'.$row3["menusubsub"].'</a></li>';
										}									
									}								
									$sub_menu .= "</ul></li>"; 
								}else{								
									$sub_menu .= '<li> <a href="'.$row2["href"].'"><i class="bx bx-right-arrow-alt"></i>'.$row2["menusub"].'</a></li>';								
								}						
							}
						}
						$sub_menu .= "</ul>";
					}else{
						$hasarrow = "";
						$sub_menu = "";
					}				
					$menu .= '<li>
								<a href="'.$row["href"].'" class="'.$hasarrow.'">
									<div class="parent-icon"><i class="'.$row["icon_class"].'"></i>
									</div>
									<div class="menu-title">'.$row["menu"].'</div>
								</a>
								'.$sub_menu.'
							</li>';
				}
			}	
			
			
		}
		
			
	} 

