		}else{
			
			$menu = "";		
		
			$query = "SELECT id_menu, menu, orden, tiene_sub, icon_class, href FROM menu ORDER BY orden";
			$qresult = DatasetSQL($query);
			while ($row = mysqli_fetch_array($qresult)){
				/* busca permiso de usuario para el menu*/
				$query_pm = "SELECT COUNT(id_permiso_menu) AS existe FROM permiso_menu WHERE id_menu = ".$row['id_menu']." AND id_tipo_usuario = ".$_SESSION['id_tipo_usuario'];
				$existe_permiso_menu = GetValueSQL($query_pm,"existe");			
				if($existe_permiso_menu > 0){
					if($row["tiene_sub"] == 1){
						$hasarrow = "has-arrow";					
						/*busca el submenu*/
						$sub_menu = "<ul>";
						$query2 = "SELECT id_menusub, menusub, href FROM menusub WHERE id_menu = ".$row['id_menu']." ORDER BY orden";
						$qresult2 = DatasetSQL($query2);
						while ($row2 = mysqli_fetch_array($qresult2)){ 
							/* busca permiso de usuario para el submenu*/
							$query_psm = "SELECT COUNT(id_permiso_submenu) AS existe FROM permiso_submenu WHERE id_submenu = ".$row2['id_menusub']." AND id_tipo_usuario = ".$_SESSION['id_tipo_usuario'];
							$existe_permiso_submenu = GetValueSQL($query_psm,"existe");			
							if($existe_permiso_submenu > 0){						
								$sub_menu .= '<li> <a href="'.$row2["href"].'"><i class="bx bx-right-arrow-alt"></i>'.$row2["menusub"].'</a></li>';
							}
						}
						$sub_menu .= "</ul>";
					}else{
						$hasarrow = "";
						$sub_menu = "";
					}
					
					$menu .= '<li>
								<a href="'.$row["href"].'" class="'.$hasarrow.'">
									<div class="parent-icon"><i class="'.$row["icon_class"].'"></i>
									</div>
									<div class="menu-title">'.$row["menu"].'</div>
								</a>
								'.$sub_menu.'
							</li>';
				}
			}	
		}	
	} 

	$result = array( 
		'menu' 		=> $menu, 
		'result' 		=> $resultStatus, 
		'result_text' 	=> $resultText
	);	 
	XML_Envelope($result);     
	exit;
