/* VERSION USUARIOS */

//	if (Requesting("action")=="valida_pagina_version_nueva"){
if (Requesting("action")=="valida_pagina"){
	
	$pagina = Requesting("pagina");
	
	$resultStatus 	= "ok"; 
	$resultText 	= "Navegacion valida";	
	$hrefs 			= "index.php";	
	
	$today = date("Y-m-d");
	$hora = date("H");
	//echo $pagina;
	
	//echo $hora;
	 
	/*busca usuario sistemas*/
	$query_tu = "SELECT id_tipo_usuario, tipo_usuario FROM tipo_usuario WHERE id_tipo_usuario = ".$_SESSION['id_tipo_usuario'];
	$tipo_de_usuario = GetValueSQL($query_tu,"tipo_usuario"); 
	$permisos_usuario = GetValueSQL($query_tu,"id_tipo_usuario").","; 
		
	//$permisos_usuario = "";
	$query1 = "SELECT id_tipo_usuario 
		FROM usuario_permiso  
		WHERE id_almacen = ".$_SESSION['id_almacen']." AND id_usuario = ".$_SESSION['id_sesion'];
	$qresult1 = DatasetSQL($query1);
	while ($row1 = mysqli_fetch_array($qresult1)){	
		$permisos_usuario .= $row1['id_tipo_usuario'].",";	
	} 
	
	$permisos_usuario = trim($permisos_usuario,",");
	
	if($tipo_de_usuario === $tipo_usuario_sistemas OR $tipo_de_usuario === $tipo_usuario_administrador OR $tipo_de_usuario === $tipo_usuario_gerente){
		$resultStatus 	= "ok"; 
		$resultText 	= "Navegacion valida";	
	}else{
		
		$query_pag = "SELECT COUNT(pagina) AS existe 
			FROM permiso_pagina 
			WHERE id_tipo_usuario IN (".$permisos_usuario.") AND pagina = '".$pagina."'";
		$existe_pagina = GetValueSQL($query_pag,"existe");
		if($existe_pagina == 0){
			$resultStatus 	= "error"; 
			$resultText 	= "Navegacion prohibida";	
			$hrefs 			= "index.php";	
		}

	}	
	
	
	 
	/* validamos que se encuentre en alguna seccion del módulo ALMACEN para hacer audtoria interna*/
	if($tipo_de_usuario === $tipo_usuario_almacen OR $tipo_de_usuario === $tipo_usuario_gerente){
			
		/*buscamos que la página visitada sea del modulo almacen*/
		$query_ma = "SELECT COUNT(id_pagina_aud) AS existe FROM auditoria_interna_paginas WHERE pagina = '".$pagina."' ";
		$existe_ma = GetValueSQL($query_ma,"existe");
		
		if($existe_ma > 0){ /* pagina de modulo ALMACEN */
						
			/* buscamos que la sucursal se deba auditar */
			$query_as = "SELECT COUNT(id_auditoria_suc) AS existe FROM auditoria_interna_sucursales WHERE id_sucursal = ".$_SESSION['id_almacen']." AND auditar = 1";
			$existe_as = GetValueSQL($query_as,"existe");
			
			if($existe_as > 0){ /* La sucursal se debe auditar */
				
				//$bloqueada = GetValueSQL($query_ma,"bloqueada");
				//$query_aib = "SELECT COUNT(id_auditoria) AS existe FROM auditoria_interna WHERE fecha_creacion = '".$today."' AND estatus = 0";
				$query_aib = "SELECT COUNT(id_auditoria) AS existe FROM auditoria_interna 
					WHERE fecha_creacion = '".$today."' 
					AND id_sucursal = ".$_SESSION['id_almacen']." 
					AND estatus = 0";
				$requiere_auditada = GetValueSQL($query_aib,"existe"); 
				
				if($requiere_auditada > 0){ /* el modulo está bloqueado por que SE NECESITA auditoria */
					
					$resultStatus 	= "error"; 
					$resultText 	= "Se requiere Auditoria";	
					$hrefs 			= "auditoria_interna.php";	
				}else{
					
					
					//echo $today;
					
					/* si NO está bloqueado, buscamos que ya se haya hecho la auditoria HOY */
					$query_ai = "SELECT COUNT(id_auditoria) AS existe FROM auditoria_interna WHERE fecha_creacion = '".$today."' AND estatus = 1";
					
					//echo $query_ai;
					$existe_auditada = GetValueSQL($query_ai,"existe"); 
					
					
					if($existe_auditada > 0){ /* ya se hizo auditoria en esta sucursal el día de hoy*/
						$resultStatus 	= "ok"; 
						$resultText 	= "Navegacion valida";	
					}else{
						/* si NO se ha hecho, y pasa de las 12 hrs hacerla */
						
						
						//echo $hora;
						
						if($hora > "12"){
							
							$query_ba = "SELECT COUNT(id_auditoria) AS existe FROM auditoria_interna WHERE fecha_creacion = '".$today."'";
							$existe_auditoria = GetValueSQL($query_ba,"existe"); 
							
							if($existe_auditoria == 0){
								$query_ca = "INSERT INTO auditoria_interna (id_sucursal, fecha_creacion, hora_creacion, hora_realizada, estatus, id_usuario) 
												VALUES(".$_SESSION['id_almacen'].", '".$today."', '".date("H:i:s")."', '00:00:00', 0, ".$_SESSION['id_sesion']." )";
								//ExecuteSQL($query_ca);
								$id_auditoria = ExecuteSQL_returnID($query_ca);
								/* crear los 5 registros a auditar al azar*/
								$query_aiv = "INSERT INTO auditoria_interna_inventario (id_auditoria, id_inventario, cantidad_exos, cantidad_fisica) VALUES ";
								$nums = 0;
								$query_inv = "SELECT id_inventario, cantidad FROM inventario WHERE id_almacen = ".$_SESSION['id_almacen']." AND cantidad > 0 ORDER BY RAND() LIMIT 10";
								
								$qresult = DatasetSQL($query_inv);
								while ($row = mysqli_fetch_array($qresult)){
									$nums++;
									$query_aiv .= "(".$id_auditoria.", ".$row['id_inventario'].", ".$row['cantidad'].", 0),";
								}	
								
								if($nums > 0){
									$consulta_query = rtrim($query_aiv, ",");	 
									ExecuteSQL($consulta_query);
								}
									
							}
							
							
							$resultStatus 	= "error"; 
							$resultText 	= "Se requiere Auditoria";	
							$hrefs 			= "auditoria_interna.php";	
					
							
						}else{
								//echo "entra";
							/* si NO pasa de las 12 hrs, hacer rutina al azar */
							$num = rand(0,1);
							if($num == 1){
								
								$query_ba = "SELECT COUNT(id_auditoria) AS existe FROM auditoria_interna WHERE fecha_creacion = '".$today."'";
								$existe_auditoria = GetValueSQL($query_ba,"existe"); 
								
								if($existe_auditoria == 0){
								
									$query_ca = "INSERT INTO auditoria_interna (id_sucursal, fecha_creacion, hora_creacion, hora_realizada, estatus, id_usuario) 
											VALUES(".$_SESSION['id_almacen'].", '".$today."', '".date("H:i:s")."', '00:00:00', 0, ".$_SESSION['id_sesion']." )";
									$id_auditoria = ExecuteSQL_returnID($query_ca);
									
									/* crear los 5 registros a auditar al azar*/
									$query_aiv = "INSERT INTO auditoria_interna_inventario (id_auditoria, id_inventario, cantidad_exos, cantidad_fisica) VALUES ";
									$nums = 0;
									$query_inv = "SELECT id_inventario, cantidad FROM inventario WHERE id_almacen = ".$_SESSION['id_almacen']." AND cantidad > 0 ORDER BY RAND() LIMIT 5";
									
									$qresult = DatasetSQL($query_inv);
									while ($row = mysqli_fetch_array($qresult)){
										$nums++;
										$query_aiv .= "(".$id_auditoria.", ".$row['id_inventario'].", ".$row['cantidad'].", 0),";
									}										
									if($nums > 0){
										$consulta_query = rtrim($query_aiv, ",");	 
										ExecuteSQL($consulta_query);
									}	
								}
								$resultStatus 	= "error"; 
								$resultText 	= "Se requiere Auditoria";	
								$hrefs 			= "auditoria_interna.php";									
							}else{
								$resultStatus 	= "ok"; 
								$resultText 	= "Navegacion valida";	
							}							
						}
					}
				}
			}
		}
	}
	
	//echo "aqui ya no:::".$resultText;
	//echo "SESION TIPO USUARIO:::".$_SESSION['id_tipo_usuario'];
