if (Requesting("action")=="valida_sesion"){
	
	$resultStatus 		= "ok"; 
	$resultText 		= "Sesion Válida";
	$id_usuario			= "0";
	$usuario 			= "0"; 
	$id_tipo_usuario 	= "0";
	$sucursal 			= "0";
	
	$dia_actual 		= date("N");
	$hora_actual 		= date("H:i:s");
	$permiso 			= 1;
	
	// oswaldoresidente 
		
	if(isset($_SESSION['id_sesion'])){
		$query = "SELECT COUNT(id_usuario) AS existe, usuario, id_tipo_usuario, activo FROM usuario WHERE id_usuario = ".$_SESSION['id_sesion'];
		$existe = GetValueSQL($query,"existe");
		
		if($existe > 0 ){
			
			/* validamos que se encuentre activo */
			$estatus_activo = GetValueSQL($query,"activo");
			if($estatus_activo == 0){
				$resultStatus 	= "error"; 
				$resultText 	= "El Usuario se encuentra BLOQUEADO. Por favor verifique con Dirección.";
			}else{			
				/* vamos a validar que tenga horario asignado*/
				$query_h = "SELECT COUNT(id_horario) AS existe FROM usuario_horario WHERE id_usuario = ".$_SESSION['id_sesion'];
				$existe_h = GetValueSQL($query_h,"existe");
				if($existe_h > 0 ){
					/* significa que el usuario SI tiene al menos un horario asignado. Ahora si buscamos que exista el permiso según día y hora actual*/
					$query_h2 = "SELECT COUNT(id_horario) AS existe 
						FROM usuario_horario 
						WHERE id_usuario = ".$_SESSION['id_sesion']." AND dia_semana = ".$dia_actual." 
							AND hora_entrada <= '".$hora_actual."' AND hora_salida >= '".$hora_actual."'";
					$existe_h2 = GetValueSQL($query_h2,"existe");
					if($existe_h2 > 0 ){
						$permiso = 1;
					}else{
						$permiso = 0;
					}
				}			
				
				$usuario 			= GetValueSQL($query,"usuario");
				$id_tipo_usuario 	= GetValueSQL($query,"id_tipo_usuario");
			
				$querys = "SELECT COUNT(id_almacen) AS existe_almacen, nombre FROM almacen WHERE id_almacen = ".$_SESSION['id_almacen'];
				$existe_almacen 	= GetValueSQL($querys,"existe_almacen");
				if($existe_almacen > 0){
					$sucursal 	= GetValueSQL($querys,"nombre");
				}else{
					$sucursal = "NO SE ENCONTRO SUCURSAL";
				}
			}
		}else{
			$resultStatus 	= "error"; 
			$resultText 	= "Sesion NO válida";
		}
	}else{
		$resultStatus 	= "error"; 
		$resultText 	= "Sesion NO válida";
	}
	
	if($id_tipo_usuario == "0" || $usuario == "0" || $permiso == "0"){
		$resultStatus 	= "error"; 
		$resultText 	= "Sesion NO válida";
	}
	 
	
	$result = array( 
		'usuario' 			=> $usuario, 
		'id_tipo_usuario' 	=> $id_tipo_usuario,   
		'sucursal' 			=> $sucursal,   
		'result' 			=> $resultStatus, 
		'result_text' 		=> $resultText
	);	 	 
	
	//echo $resultStatus;
	
	XML_Envelope($result);     
	exit;
}

  
