						AND hora_entrada < '".$hora_actual."' AND hora_salida > '".$hora_actual."'";
				$existe_h2 = GetValueSQL($query_h2,"existe");
				if($existe_h2 > 0 ){
					$permiso = 1;
				}else{
					$permiso = 0;
				}
			}
			
			if($permiso == 1){
				$id_tipo_usuario 	= GetValueSQL($query,"id_tipo_usuario");  /* tipo de usuario */
				$id_area 			= GetValueSQL($query,"id_area");  /* tipo de usuario */
				$id_almacen 		= GetValueSQL($query,"id_almacen");  /* id almacen */ 
				/*Define la pagina de inicio*/
				$query_pi = "SELECT pagina_inicio FROM tipo_usuario WHERE id_tipo_usuario = ".$id_tipo_usuario;
				$pagina_inicio = GetValueSQL($query_pi,"pagina_inicio");
				/*obtiene la bodega o almacen del usuario*/
				//$query_almacen = "SELECT id_almacen FROM area WHERE id_area = ".$id_area;
				//$id_almacen = GetValueSQL($query_almacen,"id_almacen"); 
				/* Si por cualquier motivo existe una sesión, la destruye primero */
				session_destroy();		
				session_start();
				$_SESSION['id_sesion'] 			= $id_sesion; 
				$_SESSION['id_tipo_usuario'] 	= $id_tipo_usuario;	
				$_SESSION['usuario'] 			= $login_usuario;	
				$_SESSION['id_almacen'] 		= $id_almacen;
			}else{
				$resultStatus 	= "error"; 
				$resultText 	= "Usuario fuera del horario permitido.";
			}
		
		
		}  
	}  
	 	
		//echo $_SESSION['id_tipo_usuario'];
		
	$result = array( 
		'id_sesion' 		=> $id_sesion, 
		'pagina_inicio' 	=> $pagina_inicio, 
		'id_almacen' 		=> $id_almacen,  
		'result' 			=> $resultStatus, 
		'result_text' 		=> $resultText, 
		'alias_usuario' 	=> $login_usuario 
	);	 

	XML_Envelope($result);     
	exit;
 
}  

