	$output = $dompdf->output();  
	
	file_put_contents('archivos_pdf_generados/'.$filename.'.pdf', $output); 
	$filepath = $ruta_archivos_pdf_generados.$filename.".pdf" ; 
			
			
	$result = array( 
		'filepath' 			=> $filepath, 
		'result' 			=> $resultStatus, 
		'result_text' 		=> $resultText
	);	 

	XML_Envelope($result);     
	exit;
 
}  

