	*/
	
	$query = "SELECT cirugia_pdf_impreso.kardex, usuario.usuario AS username 
		FROM cirugia_pdf_impreso 
		INNER JOIN usuario ON (usuario.id_usuario = cirugia_pdf_impreso.id_usuario_kardex)
		WHERE cirugia_pdf_impreso.id_cirugia = ".$id_cirugia;
	$qresult = DatasetSQL($query);
	while ($row = mysqli_fetch_array($qresult)){ 
		$historico .= $row["kardex"]." - ".$row["username"]."\n"; 
