if (Requesting("action")=="valida_caducos_agrega_minialmacen_cirugia"){ 
	
	$id_set			= Requesting("id_set");
	$id_cirugia		= Requesting("id_cirugia");
	
	$resultStatus 	= "ok"; 
	$resultText 	= "Correcto. El activo no tiene productos caducos ni proximos a caducar.";
	$alerta 		= "0"; 
	$alertaText 	= "El activo contiene los sigientes productos con caducidad vencida o próxima: \n\r "; 
	
	if($id_set == "0"){  
		$resultStatus 	= "Error"; 
		$resultText 	= "No se encontró el código";
	}else{		
		$query8 = "SELECT producto_set.id_inventario, producto_set.cantidad, inventario.fecha_cad, inventario.lote, producto.referencia, producto.nombre 
					FROM producto_set
					INNER JOIN inventario ON (inventario.id_inventario = producto_set.id_inventario)
					INNER JOIN producto ON (producto.id_producto = inventario.id_producto) 
					WHERE id_set = ".$id_set;
		$qresult8 = DatasetSQL($query8);
		while ($row8 = mysqli_fetch_array($qresult8)){  
			if($row8['cantidad'] > 0){ 							
				$date_hoy = date("Y-m-d");
				$date_2 = $row8['fecha_cad']; 
				$resta = strtotime($date_2) - strtotime($date_hoy);
				$dias_para_caducidad = (((($resta)/60)/60) / 24);
				
				if($dias_para_caducidad < 30){ 
					$alerta++;
					$alertaText .= "DESC: ".$row8['nombre']." - REF: ".$row8['referencia']." - LOTE: ".$row8['lote']. " \n\r ";
				} 
			}
		}		 
	}   
	
	if($alerta > 0){
		$resultStatus 	= "error"; 
		$resultText 	= "Cuidado. El activo tiene productos caducados o proximos a caducar.";
	}

	$result = array( 
		'alerta' 		=> $alerta, 
		'alertaText' 	=> $alertaText, 
		'result' 		=> $resultStatus, 
		'result_text' 	=> $resultText
	);	 

	XML_Envelope($result);     
	exit;
 
}  
  
