				/*vamos ahora a crear la imagen virtual de lo que realmente lleva el SET a la cirugia*/
				/* Guardar imagen virtual del contenido exacto del set */ 
				$query9 = "INSERT INTO cirugia_minialmacen_inv (id_cirugia_mini, id_inventario, cantidad) VALUES ";
				$query92 = "INSERT INTO para_remisionar_tmp (id_jornada, id_cirugia, id_set, id_inventario, cantidad) VALUES ";
