				$query8 = "SELECT producto_set.id_inventario, producto_set.cantidad, inventario.fecha_cad, inventario.lote, producto.referencia, producto.nombre 
							FROM producto_set
							INNER JOIN inventario ON (inventario.id_inventario = producto_set.id_inventario)
							INNER JOIN producto ON (producto.id_producto = inventario.id_producto) 
							WHERE id_set = ".$id_set;
