					if($row8['cantidad'] > 0){ 						
						$query9 .= "(".$id_cirugia_mini.", ".$row8['id_inventario'].", ".$row8['cantidad']."),";
						$query92 .= "(0, ".$id_cirugia.", ".$id_set.", ".$row8['id_inventario'].", ".$row8['cantidad']."),";
										
