if (Requesting("action")=="devolver_minialmacen_cirugia"){ 
	
	$id_set			= Requesting("id_set");
	$id_cirugia		= Requesting("id_cirugia");
	
	$resultStatus 	= "ok"; 
	$resultText 	= "Correcto";
 
	$query2 = "SELECT id_estatus_set FROM estatus_set WHERE nombre = '".$estatus_en_cirugia."' ";
	$id_estatus_en_cirugia = GetValueSQL($query2,"id_estatus_set");
	
	//$query1 = "SELECT estatus FROM almacen_set WHERE id_set = ".$id_set;
	$query1 = "SELECT estatus FROM activo_set WHERE id_set = ".$id_set;
	$id_estatus_actual = GetValueSQL($query1,"estatus"); 
	
	if($id_set == "0"){   
		$resultStatus 	= "Error"; 
		$resultText 	= "No se encontró el código";
	}else{
		
		/* primero valida que el estatus del SET sea en cirugia */
		
		if($id_estatus_actual <> $id_estatus_en_cirugia){  
			$resultStatus 	= "Error"; 
			$resultText 	= "El estatus actual del Minialmacen no corresponde. Por favor verifique que se encuentre en Cirugia.";
		}else{
			
			/* valida que el SET si se encuentre ligado a esta cirugia */
			
			$query3 = "SELECT COUNT(id_cirugia_mini) As existe FROM cirugia_minialmacen WHERE id_cirugia = ".$id_cirugia." AND id_minialmacen = ".$id_set;
			$existe = GetValueSQL($query3,"existe"); 


			if($existe > 0){
				
				$query4 = "SELECT COUNT(id_devolver_mini) AS existe FROM devolver_minialmacen WHERE id_cirugia = ".$id_cirugia." AND id_minialmacen = ".$id_set;
				$existe2 = GetValueSQL($query4,"existe"); 
				
				if($existe2 == 0){ 
					$query = "INSERT INTO devolver_minialmacen (id_cirugia, id_minialmacen, kardex, id_usuario_kardex)
							VALUES (".$id_cirugia.", ".$id_set.", NOW(), ".$_SESSION['id_sesion'].")";
					ExecuteSQL($query);
				} 
				
			}else{
				$resultStatus 	= "Error"; 
				$resultText 	= "Este minialmacen NO se encuentra ligado a esta cirugia. NO es posible devolverlo. Por favor verifique.";
			}
			
		}
	}

	$result = array( 
		'result' 			=> $resultStatus, 
		'result_text' 		=> $resultText
	);	 

	XML_Envelope($result);     
	exit;
 
} 
 
