if (Requesting("action")=="escanear_producto_set"){   
	
	$id_cirugia			= Requesting("id_cirugia");
	$codigo				= Requesting("codigo");
	
	$resultStatus 		= "ok"; 
	$resultText 		= "Correcto";
  
	$existe_traspaso 	= 0; 
	$existe_ps 			= 0;
	$longitud 			= strlen($codigo); 
	$codigo_first 		= substr($codigo,0,2);
	$codigo_17 			= substr($codigo,16,2);
			
	$codigo2 = $codigo;
	if($codigo_first == "01" && $codigo_17 == "17"){
		$codigo = substr($codigo,16,strlen($codigo));
	}
	
	$query_al = "SELECT id_almacen FROM cirugia WHERE id_cirugia = ".$id_cirugia;
	$id_almacen_cirugia = GetValueSQL($query_al,"id_almacen");  
	/* primer busco si la cirugia se traspasó a otra*/
	/* para actualizar el producto surtido a la nueva cirugia*/
	$query0 = "SELECT COUNT(id_cirugia_traspaso) AS existe, id_cirugia_destino
				FROM cirugia_traspaso
				WHERE id_cirugia_origen = ".$id_cirugia." LIMIT 1";
	$existe_traspaso = GetValueSQL($query0,"existe");  
	if($existe_traspaso > 0){
		$id_cirugia_destino = GetValueSQL($query0,"id_cirugia_destino");  
	}
		
	$cantidad = 0;
	$query1 = "SELECT COUNT(id_inventario) AS existeinv, id_inventario FROM inventario WHERE id_almacen = ".$id_almacen_cirugia." AND (codigo_2 = '".$codigo."' OR codigo_2 = '".$codigo2."' )";
	$existeinv = GetValueSQL($query1,"existeinv");  
	
	if($existeinv > 0){		
		$id_inventario = GetValueSQL($query1,"id_inventario");  
		/* primero busco el producto escaneado en los minialmacen SET*/
		$query2 = "SELECT COUNT(cirugia_minialmacen_inv.id_cirugia_inv) AS existe_ps, cirugia_minialmacen.id_minialmacen 
			FROM cirugia_minialmacen_inv  
			INNER JOIN cirugia_minialmacen ON (cirugia_minialmacen.id_cirugia_mini = cirugia_minialmacen_inv.id_cirugia_mini)
			WHERE cirugia_minialmacen.id_cirugia = ".$id_cirugia." AND cirugia_minialmacen_inv.id_inventario = ".$id_inventario;
		$existe_ps = GetValueSQL($query2,"existe_ps"); 
		//echo ":::::".$query2.":::::";
		if($existe_ps > 0){
			
			//$id_producto_set = GetValueSQL($query2,"id_producto_set");   
			$id_minialmacen = GetValueSQL($query2,"id_minialmacen"); 
			/*obtengo id_producto_set*/ 
			$queryx = "SELECT COUNT(id_producto_set) AS existe, id_producto_set FROM producto_set WHERE id_set = ".$id_minialmacen." AND id_inventario = ".$id_inventario;
			$existe_producto_set = GetValueSQL($queryx,"existe"); 
			if($existe_producto_set > 0){
				$id_producto_set = GetValueSQL($queryx,"id_producto_set"); 
			}else{
				//$id_producto_set = 0;
				$query22 = "SELECT COUNT(cirugia_minialmacen_inv.id_cirugia_inv) AS existe_ps, cirugia_minialmacen.id_minialmacen 
					FROM cirugia_minialmacen_inv  
					INNER JOIN cirugia_minialmacen ON (cirugia_minialmacen.id_cirugia_mini = cirugia_minialmacen_inv.id_cirugia_mini)
					WHERE cirugia_minialmacen.id_cirugia = ".$id_cirugia." 
					AND cirugia_minialmacen.id_minialmacen != ".$id_minialmacen."
					AND cirugia_minialmacen_inv.id_inventario = ".$id_inventario; 
					//echo $query22;
				$existe_ps2 = GetValueSQL($query22,"existe_ps"); 
				if($existe_ps2 > 0){
					$id_minialmacen = GetValueSQL($query2,"id_minialmacen"); 
					$queryx = "SELECT COUNT(id_producto_set) AS existe, id_producto_set FROM producto_set WHERE id_set = ".$id_minialmacen." AND id_inventario = ".$id_inventario;
					$existe_producto_set = GetValueSQL($queryx,"existe"); 
					if($existe_producto_set > 0){
						$id_producto_set = GetValueSQL($queryx,"id_producto_set"); 
					}else{
						$id_producto_set = 0;
					}
				}else{
					$id_producto_set = 0;
				}
			}
			
			$query3 = "SELECT COUNT(id_cirugia_consumo) AS existe, id_cirugia_consumo, cantidad 
				FROM cirugia_consumo_esc 
				WHERE id_cirugia = ".$id_cirugia." AND id_set = ".$id_minialmacen." AND id_inventario = ".$id_inventario;
			$existe = GetValueSQL($query3,"existe");  
			if($existe > 0){ 
				$cantidad 				= GetValueSQL($query3,"cantidad");  
				$id_cirugia_consumo 	= GetValueSQL($query3,"id_cirugia_consumo");  
				$nueva_cantidad 		= ($cantidad) + 1;
				$query4 = "UPDATE cirugia_consumo_esc SET cantidad = ".$nueva_cantidad." WHERE id_cirugia_consumo = ".$id_cirugia_consumo;
			}else{ 
				$query4 = "INSERT INTO cirugia_consumo_esc (id_cirugia, id_set, id_producto_set, id_inventario, cantidad, kardex, id_usuario_kardex) VALUES (
				".$id_cirugia.", ".$id_minialmacen.", ".$id_producto_set.",  ".$id_inventario.", 1, NOW(), ".$_SESSION['id_sesion'].")"; 
			}
			//echo $query4;
			ExecuteSQL($query4);
			
			if($existe_traspaso > 0){
				$id_cirugia_destino = GetValueSQL($query0,"id_cirugia_destino");  
			}
	
			
		}else{
			
			/* el producto no corresponde a surtido en SET, buscará en INSTRUMENTAL */
			
			$query2 = "SELECT COUNT(cirugia_instrumental_inv.id_cirugia_inst) AS existe_ps, cirugia_instrumental.id_instrumental
					FROM cirugia_instrumental_inv  
					INNER JOIN cirugia_instrumental ON (cirugia_instrumental.id_cirugia_instrumental = cirugia_instrumental_inv.id_cirugia_inst)
					WHERE cirugia_instrumental.id_cirugia = ".$id_cirugia." AND cirugia_instrumental_inv.id_inventario = ".$id_inventario;
			$existe_ps = GetValueSQL($query2,"existe_ps"); 
			 
			if($existe_ps > 0){
				//$id_producto_set = GetValueSQL($query2,"id_producto_set");   
				$id_instrumental = GetValueSQL($query2,"id_instrumental"); 
				/*obtengo id_producto_set*/ 
				$queryx = "SELECT id_producto_instrumental FROM producto_instrumental WHERE id_instrumental = ".$id_instrumental." AND id_inventario = ".$id_inventario;
				$id_producto_instrumental = GetValueSQL($queryx,"id_producto_instrumental"); 
				$query3 = "SELECT COUNT(id_cirugia_consumo) AS existe, id_cirugia_consumo, cantidad 
					FROM cirugia_consumo_ins_esc 
					WHERE id_cirugia = ".$id_cirugia." AND id_instrumental = ".$id_instrumental." AND id_inventario = ".$id_inventario;
				$existe = GetValueSQL($query3,"existe");  
				if($existe > 0){ 
					$cantidad 				= GetValueSQL($query3,"cantidad");  
					$id_cirugia_consumo 	= GetValueSQL($query3,"id_cirugia_consumo");  
					$nueva_cantidad 		= ($cantidad) + 1;
					$query4 = "UPDATE cirugia_consumo_ins_esc SET cantidad = ".$nueva_cantidad." WHERE id_cirugia_consumo = ".$id_cirugia_consumo;
				}else{ 
					$query4 = "INSERT INTO cirugia_consumo_ins_esc (id_cirugia, id_instrumental, id_producto_set, id_inventario, cantidad, kardex, id_usuario_kardex) VALUES (
					".$id_cirugia.", ".$id_instrumental.", ".$id_producto_instrumental.",  ".$id_inventario.", 1, NOW(), ".$_SESSION['id_sesion'].")"; 
				}
				ExecuteSQL($query4);		
				
			}else{
				
				//echo "vampos";
				/* el producto no corresponde a SET ni INSTRUMENTAL suertido. Buscará producto suelto */
				
				$query2 = "SELECT COUNT(cirugia_producto.id_cirugia_producto) AS existe_ps
					FROM cirugia_producto  
					WHERE id_cirugia = ".$id_cirugia." AND id_inventario = ".$id_inventario;
				$existe_ps = GetValueSQL($query2,"existe_ps"); 
				if($existe_ps > 0){
					
					$query3 = "SELECT COUNT(id_cirugia_consumo) AS existe, cantidad 
						FROM cirugia_consumo_material_esc 
						WHERE id_cirugia = ".$id_cirugia." AND id_inventario = ".$id_inventario;
					$existe = GetValueSQL($query3,"existe");  
					if($existe > 0){ 
						$cantidad 				= GetValueSQL($query3,"cantidad");  
						$id_cirugia_consumo 	= GetValueSQL($query3,"id_cirugia_consumo");  
						$nueva_cantidad 		= ($cantidad) + 1;
						$query4 = "UPDATE cirugia_consumo_material_esc SET cantidad = ".$nueva_cantidad." WHERE id_cirugia_consumo = ".$id_cirugia_consumo;
					}else{  
						$query4 = "INSERT INTO cirugia_consumo_material_esc (id_cirugia, id_inventario, cantidad, kardex, id_usuario_kardex) VALUES (
						".$id_cirugia.", ".$id_inventario.", 1, NOW(), ".$_SESSION['id_sesion'].")"; 
					}
					ExecuteSQL($query4);	
				}else{
					/* ahora buscar material suelto */
					$resultStatus 	= "Error"; 
					$resultText 	= "El producto escanado NO se surtió en la cirugia. Por favor verifique.";
				}
			}
		}
		
	}else{
		$resultStatus 	= "Error"; 
		$resultText 	= "Producto escaneado no existe en el sistema";
	}
	
	
	$result = array( 
		'result' 			=> $resultStatus, 
