			ExecuteSQL($query2);			
			/* al final resta el producto del inventario, ya que ahora se encuentra en el SET*/
			$nueva_cantidad_inventario = ($cantidad_inventario) - ($cantidad); 
			if($nueva_cantidad_inventario < 0){ $nueva_cantidad_inventario = 0; }
			$query4 = "UPDATE inventario SET cantidad = ".$nueva_cantidad_inventario.", kardex = NOW(), id_usuario_kardex = ".$_SESSION['id_sesion']." WHERE id_inventario = ".$id_inventario;
			ExecuteSQL($query4);
			/*registra movimiento de salida*/
			//	$query_mov = "INSERT INTO movimiento_almacen (id_inventario, tipo, cantidad, comentarios, kardex, id_usuario_kardex) VALUES  
			//			(".$id_inventario.", 0, ".$cantidad.", 'Se envia a instrumental ID ".$id_instrumental."', NOW(), ".$_SESSION['id_sesion'].")"; 
			//	ExecuteSQL($query_mov);		
 
			$query_invd = "SELECT cantidad FROM inventario WHERE id_inventario = ".$id_inventario; 
			$cantidad_despues = GetValueSQL($query_invd,"cantidad"); 
			$comentarios_movimiento_almacen = "PRODUCTO ASIGNADO AL INSTRUMENTAL ".$id_instrumental; 
			registra_movimiento_almacen($id_inventario, 0,$cantidad_inventario, $cantidad, $cantidad_despues, $comentarios_movimiento_almacen);				
			
			
			/* registra el movimiento en el historico de resurtimientos */
			$query_res_1 = "SELECT COUNT(id_registro) AS existe, id_registro, cantidad FROM resurtir_activo_historico_inv 
							WHERE id_resurtir_historico = ".$id_resurtir_historico." AND id_inventario = ".$id_inventario;
			$existe_res = GetValueSQL($query_res_1,"existe"); 
			if($existe_res > 0){
				$id_registro 			= GetValueSQL($query_res_1,"id_registro"); 
				$cantidad_actual_res 	= GetValueSQL($query_res_1,"cantidad"); 
				$nueva_cantidad_res = ($cantidad_actual_res) + ($cantidad);
				$query_res = "UPDATE resurtir_activo_historico_inv SET cantidad = ".$nueva_cantidad_res." WHERE id_registro = ".$id_registro; 
			}else{
				$query_res = "INSERT INTO resurtir_activo_historico_inv (id_resurtir_historico, id_inventario, cantidad) VALUES 
							(".$id_resurtir_historico.",".$id_inventario.",".$cantidad.")";
			} 
			ExecuteSQL($query_res);	
		
		
		}		
	}else{ 	
		$resultStatus 	= "error"; 
		$resultText 	= "No se encuentra el producto en la base de datos o no hay suficiente inventario. Verifique.";		
	}	
	$result = array( 
		'result' 			=> $resultStatus, 
		'result_text' 		=> $resultText
	);	 
	XML_Envelope($result);     
	exit;  
}   
 
