if (Requesting("action")=="registrar_merma_inventario"){ 
	
	$id_salida		= Requesting("id_salida");  
	$codigo			= Requesting("codigo");  
	$referencia		= Requesting("referencia");  
	$lote			= Requesting("lote");  
	$cantidad		= Requesting("cantidad"); 
	 
	$resultStatus 	= "ok"; 
	$resultText 	= "Correcto";	
	$existe_inv 	= "0";	
	$es_traspaso 	= "0";	 
  
	if($codigo <> ""){
		/* primero procesamos el codigo 1 para verificar formato (01)12345678901234(17)codigo2 */
		$codigo_first 	= substr($codigo,0,2);
		$codigo_17 		= substr($codigo,16,2);
		
		if($codigo_first == "01" && $codigo_17 == "17"){  /* Los codigo enviados pertenecen al segundo segmento del tipo *++12345678910* */
			$codigo_2 = substr($codigo,16,strlen($codigo));  
		}else{
			$codigo_2 = $codigo;
		}
		
		$query2 = "SELECT COUNT(id_inventario) AS existe_inv, inventario.id_inventario AS id_inv, inventario.cantidad 
			FROM inventario 
			WHERE inventario.id_almacen = ".$_SESSION['id_almacen']." 
				AND inventario.cantidad > 0
				AND (inventario.codigo_2 = '".$codigo."' OR inventario.codigo_2 = '".$codigo_2."')";
				
		$existe_inv	= GetValueSQL($query2,"existe_inv");
		
	}else if($referencia <> "" AND $lote <> ""){
		
		$query2 = "SELECT COUNT(id_inventario) AS existe_inv, inventario.id_inventario AS id_inv, inventario.cantidad 
				FROM inventario 
				INNER JOIN producto ON (producto.id_producto = inventario.id_producto)
				WHERE inventario.id_almacen = ".$_SESSION['id_almacen']." AND inventario.cantidad > 0 AND (producto.referencia = '".$referencia."' AND inventario.lote = '".$lote."')";
	
		$existe_inv	= GetValueSQL($query2,"existe_inv");
	
	}else{
		$existe_inv	= 0;  
	}
	 

	if($existe_inv > 0){ 
		$id_inventario 				= GetValueSQL($query2,"id_inv"); 		
		$cantidad_actual_inventario = GetValueSQL($query2,"cantidad"); 		
		
		//echo $cantidad_actual_inventario;
		
		/* busco registro en salida_almacen_rapida_inv_tmp por index: salida e inventario */

		$query_a = "SELECT COUNT(id_salida_inv) AS existe, id_salida_inv, cantidad 
				FROM salida_almacen_merma_inv_tmp 
				WHERE id_salida = ".$id_salida." AND id_inventario = ".$id_inventario;
		$existe_a = GetValueSQL($query_a,"existe");  	
		
		if($existe_a > 0){ /* ya existe este registro, se suma la cantidad*/
		
			$id_salida_inv 		= GetValueSQL($query_a,"id_salida_inv"); 
			$cantidad_actual 	= GetValueSQL($query_a,"cantidad"); 
			$nueva_cantidad 	= ($cantidad_actual) + ($cantidad);
			
			if($cantidad_actual_inventario < $nueva_cantidad){
				$resultStatus 	= "Error"; 
				$resultText 	= "La cantidad supera la existencia en almacen. Por favor verifique.";					
			}else{
				$query_b = "UPDATE salida_almacen_merma_inv_tmp 
					SET cantidad = ".$nueva_cantidad." 
					WHERE id_salida_inv = ".$id_salida_inv;
					ExecuteSQL($query_b); 
			}				

		}else{ /* se crea el nuevo registro*/ 
			if($cantidad_actual_inventario < $cantidad){
				$resultStatus 	= "Error";  
				$resultText 	= "La cantidad supera la existencia en almacen. Por favor verifique.";					
			}else{
				$query_b = "INSERT INTO salida_almacen_merma_inv_tmp (id_salida, id_inventario, cantidad) 
					VALUES (".$id_salida.", ".$id_inventario.", ".$cantidad.")";	
				ExecuteSQL($query_b); 
			}
		}
 		
	}else{
		$cantidad 		= "0"; 
		$nueva_cantidad = "0";
		$resultStatus 	= "Error"; 
		$resultText 	= "No hay productos relacionados en inventario.";	
	} 

	$result = array( 
		'result' 		=> $resultStatus, 
		'result_text' 	=> $resultText
	);	 

	XML_Envelope($result);     
	exit;
 
}  
 
