			$query2 = "UPDATE inventario SET cantidad = ".$nueva_cantidad.", kardex = NOW(), id_usuario_kardex = ".$_SESSION['id_sesion']." WHERE id_inventario = ".$id_inventario;
			ExecuteSQL($query2);			
			/* registra el movimiento */		
			$query_mov = "INSERT INTO movimiento_almacen (id_inventario, tipo, cantidad, comentarios, kardex, id_usuario_kardex) VALUES 
			(".$id_inventario.", 0, ".$cantidad.", 'Salida rapida de almacen', NOW(), ".$_SESSION['id_sesion'].")"; 
			ExecuteSQL($query_mov);
			
			$query_historico_1 = "SELECT COUNT(id_salida_inv) AS existe, id_salida_inv, cantidad 
				FROM salida_almacen_rapida_inv 
				WHERE id_salida = ".$id_salida." AND id_inventario = ".$id_inventario;
			$existe_salida	= GetValueSQL($query_historico_1,"existe"); 
			if($existe_salida > 0){
				$cantidad_actual	= GetValueSQL($query_historico_1,"cantidad"); 
				$id_salida_inv		= GetValueSQL($query_historico_1,"id_salida_inv"); 
				$nueva_cantidad 	= ($cantidad_actual) + ($cantidad);
				$query_historico 	= "UPDATE salida_almacen_rapida_inv SET cantidad = ".$nueva_cantidad." WHERE id_salida_inv = ".$id_salida_inv;
				ExecuteSQL($query_historico);
			}else{			
				$query_historico = "INSERT INTO salida_almacen_rapida_inv (id_salida, id_inventario, cantidad, kardex, id_usuario_kardex)
					VALUES (".$id_salida.", ".$id_inventario.", ".$cantidad.", NOW(), ".$_SESSION['id_sesion'].")";
				ExecuteSQL($query_historico);
			}
			
			if($es_traspaso == 1){ /*generamos movimietno de traspaso*/
				
			}
		}
		
	}else{
		$cantidad 		= "0"; 
		$nueva_cantidad = "0";
		$resultStatus 	= "Error"; 
		$resultText 	= "No hay productos relacionados en inventario.";	
	} 

	$result = array( 
		'result' 		=> $resultStatus, 
		'result_text' 	=> $resultText
	);	 

	XML_Envelope($result);     
	exit;
 
}  
 
  
