if (Requesting("action")=="buscar_entrada_referencia"){  
	 
	$entrada_codigo	= Requesting("entrada_codigo");  
	$folio			= Requesting("folio");  
	
	$resultStatus 	= "ok"; 
	$resultText 	= "Busqueda de entrada_codigo";	  			
	 
	$query = "SELECT COUNT(id_instrumental) AS existe, nombre FROM instrumental WHERE codigo = '".$entrada_codigo."'";
	$existe	= GetValueSQL($query,"existe"); 
	if($existe > 0){
		$referencia	= GetValueSQL($query,"nombre");
	}else{
		$query = "SELECT COUNT(id_equipo) AS existe, nombre FROM equipo_poder WHERE codigo = '".$entrada_codigo."'";
		$existe	= GetValueSQL($query,"existe"); 
		if($existe > 0){
			$referencia	= GetValueSQL($query,"nombre");
		}else{
			$query = "SELECT COUNT(id_set) AS existe, nombre FROM almacen_set WHERE codigo = '".$entrada_codigo."'";
			$existe	= GetValueSQL($query,"existe"); 
			if($existe > 0){ 
				$referencia	= GetValueSQL($query,"nombre");
			}else{
			
				$referencia		= ""; 
				$resultStatus 	= "error"; 
				$resultText 	= "No se encontro la referencia";	
			}
		}
	}
	
	
	/* busca que exista una salida relacionada */
	$query3 = "SELECT COUNT(id_salida) AS existe FROM registros_rapidos_salida WHERE id_registro = ".$folio." AND codigo = '".$entrada_codigo."'";
	$existe3 = GetValueSQL($query3,"existe"); 	
	if($existe3 > 0){
		
		/* ahora busca que no se haya registrado ya como salida*/
		$query4 = "SELECT COUNT(id_entrada) AS existe FROM registros_rapidos_entrada WHERE id_registro = ".$folio." AND codigo = '".$entrada_codigo."'";
		$existe4 = GetValueSQL($query4,"existe"); 	
		if($existe4 == 0){
			/* ahora agrega el registro en registros_rapidos_salida */
			$query2 = "INSERT INTO registros_rapidos_entrada (id_registro, codigo) VALUES (".$folio.", '".$entrada_codigo."')"; 
			ExecuteSQL($query2);
		}else{
			$resultStatus 	= "error"; 
			$resultText 	= "Este articulo ya se encuentra registrado.";	  		
		}
	}else{
		$resultStatus 	= "error"; 
		$resultText 	= "Este articulo NO está relacionado a este registro. No se le dio salida.";	  			
	}
	
	
	
	$result = array( 
		'referencia' 		=> $referencia,  
		'result' 			=> $resultStatus, 
		'result_text' 		=> $resultText
	);	 

	XML_Envelope($result);     
	exit; 
  
}  
