if (Requesting("action")=="buscar_referencia_por_codigo"){ 
	
	$codigo_1		= Requesting("codigo_1");	
	$resultStatus 	= "ok"; 
	$resultText 	= "Busqueda de producto";		
	$referencia 	= "NA";
	$lote 			= "NA";


	$longitud 	= strlen($codigo_1); 
	$codigo_first = substr($codigo_1,0,2);
	$codigo_17 = substr($codigo_1,16,2);
			
	if($codigo_first == "01" && $codigo_17 == "17"){  /* Los codigo enviados pertenecen al segundo segmento del tipo *++12345678910* */
		//$codigo_1 = substr($codigo_1,0,16);
		//$codigo_2 = substr($codigo_1,16,strlen($codigo_1 - 16));
		$codigo_2 = substr($codigo_1,16,strlen($codigo_1));
		$codigo_3 = substr($codigo_1,16,strlen($codigo_1));  
	}else{
		$codigo_2 = $codigo_1;
		$codigo_3 = $codigo_1;
	}
	
	$query = "SELECT COUNT(id_inventario) AS existe, inventario.lote, producto.referencia
		FROM inventario  
		INNER JOIN producto ON (producto.id_producto = inventario.id_producto) 
		WHERE inventario.id_almacen = ".$_SESSION['id_almacen']." 
		AND (inventario.codigo_2 = '".$codigo_1."' OR inventario.codigo_2 = '".$codigo_2."' OR inventario.codigo_2 = '".$codigo_3."')";
	$existe = GetValueSQL($query,"existe");  
	if($existe > 0){	 	
		$referencia = GetValueSQL($query,"referencia");  
		$lote 		= GetValueSQL($query,"lote");  
	} 
	
	$result = array(
		'referencia' 	=> $referencia,  
		'lote' 			=> $lote, 
		'result' 		=> $resultStatus, 
		'result_text' 	=> $resultText
	);	 
