/* esta funcion hace una copia de inventario_tmp hacia inventario, ademas de registrar el movimiento en el hostorico */
if (Requesting("action")=="guardar_registro_entrada"){   
		
	$id_entrada 	= Requesting("id_entrada");
	$resultStatus 	= "ok"; 
	$resultText 	= "Busqueda de producto";	
	
	$cantidad_actual_cai 	= "0";	
	$id_inventario 			= "0";	
	
	$mes = date('m');
	$anio = date('Y'); 
				
	$query1 = "SELECT COUNT(id_entrada) AS existe_entrada, id_fabricante, es_compra, factura  
		FROM entrada_almacen 
		WHERE id_entrada = ".$id_entrada." AND estatus = 1";
	$existe_entrada = GetValueSQL($query1,"existe_entrada");
	
	if($existe_entrada > 0){
		$proveedor = GetValueSQL($query1,"id_fabricante");
		$es_compra = GetValueSQL($query1,"es_compra");
		$factura = GetValueSQL($query1,"factura");

		$query = "SELECT id_inventario, id_entrada, id_producto, codigo_2, lote, fecha_cad, id_area, id_subarea, nivel, cantidad, precio 
			FROM inventario_tmp 
			WHERE id_entrada = ".$id_entrada;
		$qresult = DatasetSQL($query);		
		while ($row = mysqli_fetch_array($qresult)){		
			/* busca que el prod ya este registrado en inventario*/
			$query_cai = "SELECT COUNT(id_inventario) AS existe, cantidad, id_inventario 
				FROM inventario 
				WHERE  id_almacen = ".$_SESSION['id_almacen']." AND 
				id_producto = ".$row['id_producto']." AND codigo_2 = '".$row['codigo_2']."' AND lote = '".$row['lote']."' 
				AND fecha_cad = '".$row['fecha_cad']."'";
			$existe_actual_cai = GetValueSQL($query_cai,"existe"); 
			if($existe_actual_cai > 0){ 
				$cantidad_actual_cai 	= GetValueSQL($query_cai,"cantidad");  
				$id_inventario 			= GetValueSQL($query_cai,"id_inventario"); 				
				if($cantidad_actual_cai < 0){
					$cantidad_actual_cai = 0;
				}				
				$cantidad_cai = ($cantidad_actual_cai) + ($row['cantidad']);  
				$query2 = "UPDATE inventario SET cantidad = ".$cantidad_cai.", kardex = NOW(), id_usuario_kardex = ".$_SESSION['id_sesion']." WHERE id_inventario = ".$id_inventario;
				ExecuteSQL($query2);  
			}else{ 
				$query2 = "INSERT INTO inventario (id_producto, id_fabricante, codigo_2, lote, fecha_cad, id_almacen, id_area, id_subarea, nivel, cantidad, kardex, id_usuario_kardex)
					VALUES (".$row['id_producto'].", ".$proveedor.", '".$row['codigo_2']."', '".$row['lote']."', '".$row['fecha_cad']."', ".$_SESSION['id_almacen'].",
					".$row['id_area'].", ".$row['id_subarea'].", '".$row['nivel']."', ".$row['cantidad'].", NOW(), ".$_SESSION['id_sesion'].")";				
				$id_inventario = ExecuteSQL_returnID($query2);  
			} 			
			/* registra el movimiento */		 
			//	$query_mov = "INSERT INTO movimiento_almacen (id_inventario, tipo, cantidad, comentarios, kardex, id_usuario_kardex) 
			//				VALUES (".$id_inventario.", 1, ".$row['cantidad'].", 'Nueva entrada ID ".$id_entrada."', NOW(), ".$_SESSION['id_sesion'].")";
			//	ExecuteSQL($query_mov); 
	
			$query_invd = "SELECT cantidad FROM inventario WHERE id_inventario = ".$id_inventario; 
			$cantidad_despues = GetValueSQL($query_invd,"cantidad");  
			$comentarios_movimiento_almacen = "ENTRADA (ANTERIOR) - ".$factura." - ".$id_entrada; 
			registra_movimiento_almacen($id_inventario, 1,$cantidad_actual_cai, $row['cantidad'], $cantidad_despues, $comentarios_movimiento_almacen);
								 
			$query_entrada_producto = "INSERT INTO entrada_almacen_producto (id_entrada, id_inventario, cantidad) VALUES(".$id_entrada.", ".$id_inventario.", ".$row['cantidad'].")";
			ExecuteSQL($query_entrada_producto);
		
			/*update a entrada_almacen para estatus archivada*/
			$query_up = "UPDATE entrada_almacen SET estatus = 2 WHERE id_entrada = ".$id_entrada;
			ExecuteSQL($query_up); 		
		
			if($es_compra == "1"){  /* Registra la compra */  				
				/* busca referencia*/
				$query_br = "SELECT referencia FROM producto WHERE id_producto = ".$row['id_producto'];
				$referencia = GetValueSQL($query_br,"referencia"); 
				/*busca registro actual de la compra relacion con producto y fecha*/
				$query_bc = "SELECT COUNT(id_compra) AS existe, id_compra, cantidad FROM compras WHERE 
								mes= ".$mes." AND anio = ".$anio." AND id_producto = ".$row['id_producto']." AND precio = ".$row['precio']."";
				$existe_bc = GetValueSQL($query_bc,"existe");  
				if($existe_bc > 0){  
					$id_compra = GetValueSQL($query_bc,"id_compra");  
					$cantidad_bc_actual = GetValueSQL($query_bc,"cantidad");   
					$cantidad_bc_nueva = ($cantidad_bc_actual) + ($row['cantidad']);
					$query_compra = "UPDATE compras  
						SET cantidad = ".$cantidad_bc_nueva." ,
						kardex = NOW(), id_usuario_kardex = ".$_SESSION['id_sesion']."
						WHERE id_compra = ".$id_compra;
				}else{
					$query_compra = "INSERT INTO compras (fecha, mes, anio, id_producto, referencia, cantidad, precio, kardex, id_usuario_kardex)
					VALUES (NOW(), ".$mes.", ".$anio.", ".$row['id_producto'].", '".$referencia."', ".$row['cantidad'].", ".$row['precio'].", NOW(), ".$_SESSION['id_sesion']." )";
				}  
				ExecuteSQL($query_compra);   
			}	
		} 
	}
	
	$result = array(
		'id_entrada' 	=> $id_entrada,  
		'result' 		=> $resultStatus, 
		'result_text' 	=> $resultText
	);	 
	XML_Envelope($result);     
	exit;
}
 
 
