	$remision_id_cirugia    = Requesting("remision_id_cirugia");   
	$resultStatus 	= "ok";
	$resultText 	= "Correcto."; 
		
	$query = "SELECT cirugia.fecha_programacion, cirugia.codigo, cirugia.fecha_cirugia, cirugia.paciente, cirugia.paciente_p, cirugia.paciente_m, cirugia.municipio, 
	vendedor.nombre AS vendedor_name, tecnico.nombre AS tecnico_name, medico.nombre AS medico_name, medico.paterno AS medico_paterno, medico.materno AS medico_materno,
	estado.nombre AS estado_name, hospital.nombre AS hospital_name
	FROM cirugia 
	INNER JOIN vendedor ON (vendedor.id_vendedor = cirugia.id_vendedor)
	INNER JOIN tecnico ON (tecnico.id_tecnico = cirugia.id_tecnico)
	INNER JOIN medico ON (medico.id_medico = cirugia.id_medico) 
	INNER JOIN hospital ON (hospital.id_hospital = cirugia.id_hospital)
	INNER JOIN estado ON (estado.id_estado = cirugia.id_estado) 
	WHERE cirugia.id_cirugia = ".$remision_id_cirugia;
	
	$fecha_programacion 	= GetValueSQL($query,"fecha_programacion");  
	$fecha_cirugia 			= GetValueSQL($query,"fecha_cirugia");  
	$paciente 				= GetValueSQL($query,"paciente")." ".GetValueSQL($query,"paciente_p")." ".GetValueSQL($query,"paciente_m");  
