/* Registros Rapidos */
if (Requesting("action")=="llenar_formulario_registro_rapido"){  
	$registro_rapido_folio    = Requesting("registro_rapido_folio");  
	$resultStatus 	= "ok";
	$resultText 	= "Correcto."; 
		
	$query = "SELECT fecha, entrego, recibe, agente, comentarios, hospital, estatus FROM registros_rapidos WHERE id_registro = ".$registro_rapido_folio;
	
	$fecha 			= GetValueSQL($query,"fecha");  
	$entrego 		= GetValueSQL($query,"entrego");  
	$hospital 		= GetValueSQL($query,"hospital");  
	$estatus 		= GetValueSQL($query,"estatus"); 
	$recibe 		= GetValueSQL($query,"recibe"); 
	$agente 		= GetValueSQL($query,"agente");  
	$comentarios 	= GetValueSQL($query,"comentarios"); 
	 
	 
	/* buscar numero de cajas */
	$cajas_salida 	= 0;
	$cajas_entrada 	= 0;
 
	$query = "SELECT codigo FROM registros_rapidos_salida WHERE id_registro = ".$registro_rapido_folio;
	$qresult = DatasetSQL($query);
	while ($row = mysqli_fetch_array($qresult)){
		$cajas_salida++;
		$query2 = "SELECT COUNT(codigo) AS existe FROM registros_rapidos_entrada WHERE id_registro = ".$registro_rapido_folio." AND codigo = '".$row['codigo']."'";
		$existe = GetValueSQL($query2,"existe");
		
		if($existe > 0){
			$cajas_entrada++;
		}else{
			$resultStatus 	= "ok"; 
			$resultText 	= "Los registros de entrada NO corresponden a los de salida.";
		}
		
		
	}
	
	$result = array(    
		'fecha' 			=> $fecha,  
		'entrego' 			=> $entrego,  
		'hospital' 			=> $hospital,   
		'estatus' 			=> $estatus,   
		'comentarios' 		=> $comentarios,   
		'agente' 			=> $agente,   
		'recibe' 			=> $recibe,   
		'cajas_salida' 		=> $cajas_salida,   
		'cajas_entrada' 	=> $cajas_entrada,    
		'result' 			=> $resultStatus, 
		'result_text' 		=> $resultText 
	);		
	XML_Envelope($result);  
	exit;		
} 
 
