if (Requesting("action")=="llenar_datos_dashboard"){  
	$resultStatus 	= "ok";
	$resultText 	= "Correcto."; 
		
	//$dashboard = "Este es el contenido del div del dash::::".$_SESSION['id_sesion'];
	$pdfs 	= ""; 
	$urls 	= "";
	$fotos 	= ""; 
	$dashboard = '<h6 class="mb-0 text-uppercase">Avisos</h6><hr>';
	
	$query = "SELECT aviso.id_aviso, aviso.fecha, aviso.texto, usuario.nombre
		FROM aviso
		INNER JOIN usuario ON (usuario.id_usuario = aviso.id_usuario)
		WHERE aviso.activo = 1";
	$qresult = DatasetSQL($query);
	while ($row = mysqli_fetch_array($qresult)){
		
		$id_aviso = $row["id_aviso"]; 
		
		/*	PDFs	*/
		$query_pdf = "SELECT id_registro, url FROM aviso_pdf WHERE id_aviso = ".$id_aviso;
		$qresult_pdf = DatasetSQL($query_pdf); 
		while ($row_pdf = mysqli_fetch_array($qresult_pdf)){
			//	$pdfs .= "<a href='".$url_base."".$row_pdf['url']."' target='_blank'>".$row_pdf['url']."</a><br>";
			$pdfs .= "<iframe src='".$url_base."".$row_pdf['url']."' width='100%' height='100%'></iframe><br>";
		}	 
		/*	URLs	*/
		$query_url = "SELECT id_registro, url FROM aviso_url WHERE id_aviso = ".$id_aviso;
		$qresult_url = DatasetSQL($query_url);  
		while ($row_url = mysqli_fetch_array($qresult_url)){
			$urls .= "<a href='".$row_url['url']."' target='_blank'>".$row_url['url']."</a><br>";
		}	 
		 
		/*	FOTOS	*/
		$query_foto = "SELECT id_registro, url FROM aviso_foto WHERE id_aviso = ".$id_aviso;
		$qresult_foto = DatasetSQL($query_foto);  
		while ($row_foto = mysqli_fetch_array($qresult_foto)){
			//	$urls .= "<a href='".$row_url['url']."' target='_blank'>".$row_url['url']."</a><br>";
			
			$foto_url = str_replace(" ","%20",$row_foto['url']);
			
			$fotos .= "  
				<div class='col-4'>
					<a href='".$row_foto['url']."' target='_blank'>
						<img src=".$foto_url." class='img-fluid'>
					</a>
				</div>";
				
			$foto_url = "";
		}	 
		 
		//	$dashboard .= " 
		//		<tr>    
		//			<td>".$row["texto"]."</td> 
		//			<td>".$row["nombre"]."</td> 
		//			<td>".$row["fecha"]."</td> 
		//			<td>".$pdfs."</td> 
		//			<td>".$urls."</td> 
		//			<td><a href='ver_fotos_avisos.php?id_aviso=".$row['id_aviso']."' target='_blank' class='btn btn-info' data-toggle='tooltip' title='ver fotos'>Ver Fotos</a></td>  
		//		</tr>
		//	";	
		
		$dashboard .= '
					<div class="row">
						<div class="col-12 col-lg-9 mx-auto">
							<div class="card radius-10">
								<div class="card-body">
									<div class="d-flexx align-items-center">
										<div class="row">
											<div class="col-6">
												<div class="flex-grow-1 ms-3">
													<h4 class="mt-0">'.$row["fecha"].'</h4>
													<h6 class="mt-0">Enviado por : '.$row["nombre"].'</h6>
													<p class="mb-0">'.nl2br($row["texto"]).'</p>
												</div>
											</div>
											<div class="col-6">
												'.$pdfs.'
											</div>
										</div>
										<hr><div class="row">'.$urls.'</div>
										<hr><div class="row">'.$fotos.'</div>
									</div>
								</div>
							</div>						
						</div>							
					</div>';

		$pdfs 	= "";
		$urls 	= "";
		$fotos 	= "";
	
	}	  
	
	
 
	$result = array(   
		'dashboard' 	=> $dashboard,  
		'result' 		=> $resultStatus, 
		'result_text' 	=> $resultText
	);		
	XML_Envelope($result);  
	exit;		
}
 
