if (Requesting("action")=="recibir_material"){ 

	$id_cirugia 	= Requesting("id_cirugia"); 
	$id_tecnico 	= Requesting("id_tecnico"); 
	$id_vendedor 	= Requesting("id_vendedor"); 
	$folio 			= Requesting("folio"); 

	$continua 		= 1;  
	$resultStatus 	= "ok";
	$resultText 	= "Correcto"; 
	
	$today = date("Y-m-d H:i:s");
	
	$query = "SELECT COUNT(id_devolver) AS existe FROM devolver_material WHERE id_cirugia = ".$id_cirugia;
	$existe = GetValueSQL($query, "existe");
	if($existe == 0){  
	
		/* busco el folio */
		$query_f = "SELECT COUNT(id_devolver) AS existe_f FROM devolver_material WHERE folio = '".$folio."'";
		$existe_f = GetValueSQL($query_f, "existe_f");
		if($existe_f > 0){
			$resultStatus 	= "Error"; 
			$resultText 	= "El folio ".$folio." ya existe en el sistema. Utilice otro"; 
		}else{
			/* primero busco hora de programacion de la cirugia, y lo comparo con la hora actual*/
			$query0 = "SELECT COUNT(id_registro) AS existe, fecha_nueva FROM cirugia_reprogramada WHERE id_cirugia = ".$id_cirugia;
			$existe_rep = GetValueSQL($query0, "existe");
			if($existe_rep > 0){
				$fecha_cirugia = GetValueSQL($query0, "fecha_nueva");
			}else{
				$query1 = "SELECT fecha_cirugia FROM cirugia WHERE id_cirugia = ".$id_cirugia;
				$fecha_cirugia = GetValueSQL($query1, "fecha_cirugia");
			}
			
			/*resto tiempo*/
			$fechaInicialSegundos = strtotime($fecha_cirugia);
			$fechaFinalSegundos = strtotime($today); 
			$dias = ($fechaFinalSegundos - $fechaInicialSegundos) / 86400;
			
			$horas = ($dias * 24);
			
			$horas = round($horas,0, PHP_ROUND_HALF_DOWN);
	
			$query2 = "INSERT INTO devolver_material (id_cirugia,  id_tecnico, id_vendedor, tiempo_total, folio, kardex, id_usuario_kardex) VALUES 
					(".$id_cirugia.", ".$id_tecnico.", ".$id_vendedor.", ".$horas.", '".$folio."', NOW(), ".$_SESSION['id_sesion'].")";
			ExecuteSQL($query2);
		} 
		
		
	}else{
		$resultStatus 	= "Error"; 
