if (Requesting("action")=="finalizar_cirugia"){  
	$consumo_string		= Requesting("consumo_string"); 
	$id_cirugia 		= Requesting("id_cirugia"); 

	$resultStatus 	= "ok";
	$resultText 	= "Correcto.";
 
	$consumos = explode(",", $consumo_string);			
	foreach ($consumos as &$valor) {
		if($valor != ""){
			
			$porciones = explode("|", $valor);
			$id_producto_set = $porciones[0];
			$cantidad_consumo = $porciones[1];
			
			
			$query0 = "SELECT COUNT(id_cirugia_consumo) AS existe FROM cirugia_consumo WHERE id_cirugia = ".$id_cirugia." AND id_producto_set = ".$id_producto_set;
			$existe = GetValueSQL($query0, "existe");
			
			if($existe == 0){
				$query = "INSERT INTO cirugia_consumo (id_cirugia, id_setm id_producto_set, id_inventario, cantidad, kardex, id_usuario_kardex) VALUES 
						(".$id_cirugia.", 0, ".$id_producto_set.", 0, ".$cantidad_consumo.", NOW(), ".$_SESSION['id_sesion'].")";
			}else{
				$query = "UPDATE cirugia_consumo SET cantidad = ".$cantidad_consumo." WHERE id_cirugia = ".$id_cirugia." AND id_producto_set = ".$id_producto_set;
			}
			ExecuteSQL($query);
			
			/* restar de producto_set */ 
			$query2 = "SELECT id_set, cantidad FROM producto_set WHERE id_producto_set = ".$id_producto_set;
			$id_set = GetValueSQL($query2, "id_set"); 
			$cantidad_actual = GetValueSQL($query2, "cantidad");
			$nueva_cantidad = ($cantidad_actual) - ($cantidad_consumo);
			
			$query3 = "UPDATE producto_set SET cantidad = ".$nueva_cantidad." WHERE id_producto_set = ".$id_producto_set;
			ExecuteSQL($query3);
			
			$query7 = "SELECT COUNT(id_resurtir) AS existe FROM resurtir_set WHERE id_cirugia = ".$id_cirugia." AND id_producto_set = ".$id_producto_set;
			$existe_resurtir = GetValueSQL($query7, "existe");
			if($existe_resurtir == 0){
				$query4 = "INSERT INTO resurtir_set (id_cirugia, id_producto_set, id_inventario, cantidad) VALUES (".$id_cirugia.", ".$id_producto_set.", 0, ".$cantidad_consumo.")";				
			}else{
				$query4 = "UPDATE resurtir_set SET cantidad = ".$cantidad_consumo." WHERE  id_cirugia = ".$id_cirugia." AND id_producto_set = ".$id_producto_set;
			}
			ExecuteSQL($query4);
			/* cambiar estatus del set */
			$query5 = "SELECT id_estatus_set FROM estatus_set WHERE nombre = '".$estatus_resurtir."'";
			$id_estatus_set = GetValueSQL($query5, "id_estatus_set"); 
			
			$query6 = "UPDATE almacen_set SET estatus = ".$id_estatus_set." WHERE id_set = ".$id_set;
			ExecuteSQL($query6); 
			
		}
	} 	
	
	$result = array(  
		'result' 				=> $resultStatus,  
		'result_text' 			=> $resultText
	);		
	XML_Envelope($result); 
	exit; 
	
}
 
