/*hospital*/
if (Requesting("action")=="guardar_hospital"){ 
	$tipo					= Requesting("tipo"); 
	$nuevo_hospital_id 		= Requesting("nuevo_hospital_id");
	$nuevo_hospital_nombre 	= Requesting("nuevo_hospital_nombre"); 
	$nuevo_hospital_prepago 	= Requesting("nuevo_hospital_prepago");
	$nuevo_hospital_sucursal 	= Requesting("nuevo_hospital_sucursal");
	$resultStatus 	= "ok";
	$resultText 	= "Correcto.";	
		
	$querye = "SELECT COUNT(id_hospital) AS existe FROM hospital WHERE nombre = '".$nuevo_hospital_nombre."'";
	$existe = GetValueSQL($querye,"existe");
	
	if($tipo == "nuevo" || $tipo == "nuevo_salir"){
		if($nuevo_hospital_id == "0"){ 
			if($existe >= 1){
				$resultStatus 	= "error";
				$resultText 	= "Ya existe este hospital. Utiliza otro nombre."; 
			}else{	
				$query = "INSERT INTO hospital (nombre, prepago, id_almacen, kardex, id_usuario_kardex) 
				VALUES ('".$nuevo_hospital_nombre."', ".$nuevo_hospital_prepago.", ".$nuevo_hospital_sucursal.",  NOW(), ".$_SESSION['id_sesion'].")";
				ExecuteSQL($query); 	
			}
		}else{
			$query = "UPDATE hospital SET nombre = '".$nuevo_hospital_nombre."', 
				prepago = ".$nuevo_hospital_prepago.", 
				id_almacen = ".$nuevo_hospital_sucursal.",
				kardex = NOW(), id_usuario_kardex = ".$_SESSION['id_sesion']." WHERE id_hospital = ".$nuevo_hospital_id ;
			ExecuteSQL($query); 	
		}		
	}else if($tipo == "editar"){  
		if($nuevo_hospital_id == "0"){   
			if($existe >= 1){
				$resultStatus 	= "error";
				$resultText 	= "Ya existe este hospital. Utiliza otro nombre.";
			}else{	
				$query = "INSERT INTO hospital (nombre, prepago, kardex, id_usuario_kardex) VALUES 
				('".$nuevo_hospital_nombre."', ".$nuevo_hospital_prepago.", ".$nuevo_hospital_sucursal.", NOW(), ".$_SESSION['id_sesion'].")";
				/*obtiene el ID del nuevo registro*/
				$nuevo_hospital_id = ExecuteSQL_ReturnID($query); 
			} 
		}else{
			$query = "UPDATE hospital SET nombre = '".$nuevo_hospital_nombre."', prepago = ".$nuevo_hospital_prepago.", 
			id_almacen = ".$nuevo_hospital_sucursal.",kardex = NOW(), id_usuario_kardex = ".$_SESSION['id_sesion']." WHERE id_hospital = ".$nuevo_hospital_id ;
			ExecuteSQL($query); 	 
		}			
	}
		
	$result = array(  
		'nuevo_hospital_id' 	=> $nuevo_hospital_id,    
		'result' 				=> $resultStatus,  
		'result_text' 			=> $resultText
	);		
	XML_Envelope($result); 
	exit; 	
} 
