				$resultStatus 	= "error";
				$resultText 	= "Ya existe este vendedor. Utiliza otro nombre.";
			}else{	
				$query = "INSERT INTO vendedor (id_usuario, nombre, programar, activo,  kardex, id_usuario_kardex)
					VALUES (".$nuevo_vendedor_usuario.", '".$nuevo_vendedor_nombre."', 0, ".$nuevo_vendedor_activo.", NOW(), ".$_SESSION['id_sesion'].")";
				/*obtiene el ID del nuevo registro*/
				$nuevo_vendedor_id = ExecuteSQL_ReturnID($query); 
			}
		}else{
			//echo "usuario".$nuevo_vendedor_usuario;
			//echo "vendedor".$nuevo_vendedor_id;
			/* busca que el usuario no este relacionado a otro vendedor*/
			$query_bv = "SELECT COUNT(id_vendedor) AS existe_vendedor FROM vendedor WHERE id_usuario = ".$nuevo_vendedor_usuario." AND id_vendedor <> ".$nuevo_vendedor_id;
