if (Requesting("action")=="llenar_tabla_merma_almacen_tmp"){  
	
	$id_salida = Requesting("id_salida"); 
	
	$resultStatus 	= "ok";
	$resultText 	= "Correcto.";	  
	$xmlRow 		= "";	 
	$acciones 		= "si"; 
	
	$num_row = 0; 
	 
	$query = "SELECT salida_almacen_merma_inv_tmp.id_salida_inv, salida_almacen_merma_inv_tmp.cantidad, inventario.codigo_2, inventario.lote, inventario.fecha_cad, producto.referencia, producto.nombre
		FROM salida_almacen_merma_inv_tmp 
		INNER JOIN inventario ON (inventario.id_inventario = salida_almacen_merma_inv_tmp.id_inventario)
		INNER JOIN producto ON (producto.id_producto = inventario.id_producto)
		WHERE salida_almacen_merma_inv_tmp.id_salida = ".$id_salida;
	
	$qresult = DatasetSQL($query); 
	while ($row = mysqli_fetch_array($qresult)){
		$xmlRow .= '
			<tr>
				<td>'.$row["nombre"].'</td>  
				<td>'.$row["referencia"].'</td>  
				<td>'.$row["codigo_2"].'</td>  
				<td>'.$row["lote"].'</td>   
				<td>'.$row["fecha_cad"].'</td>     
				<td>'.$row["cantidad"].'</td>    
				<td>
					<a href="javascript:eliminar_merma_almacen_tmp('.$row["id_salida_inv"].')" class="btn btn-danger" data-toggle="tooltip" title="eliminar"><i class="fa fa-pencil"></i> ELIMINAR </a>
				</td> 
			</tr>  
		'; 
		
		$num_row = ($num_row) + ($row["cantidad"]);
	}	 	
	
	$result = array(    
		'table_salida_almacen' 	=> $xmlRow,   
		'cant_articulos' 		=> $num_row, 
		'acciones' 				=> $acciones, 
		'result' 				=> $resultStatus, 
		'result_text' 			=> $resultText
	);		
	XML_Envelope($result);     
	exit;	
}
 
