if (Requesting("action")=="llenar_tabla_permisos_subsubmenu"){ 
	
	$id_menusub = Requesting("id_menusub"); 
	$id_almacen = Requesting("id_almacen"); 
	$id_tipo_usuario = Requesting("id_tipo_usuario"); 
	
	$resultStatus 	= "ok";
	$resultText 	= "Correcto.";	  
	$xmlRow 		= "";	 
	$acciones 		= "si";  
	 
	$query = "SELECT permiso_subsubmenu.id_permiso, menusubsub.menusubsub, menusubsub.id_menusubsub  
		FROM permiso_subsubmenu
		INNER JOIN menusubsub ON (menusubsub.id_menusubsub = permiso_subsubmenu.id_subsubmenu)
		WHERE permiso_subsubmenu.id_almacen = ".$id_almacen." AND permiso_subsubmenu.id_tipo_usuario = ".$id_tipo_usuario." AND menusubsub.id_menusub = ".$id_menusub."  ORDER BY menusubsub.menusubsub";
	$qresult = DatasetSQL($query); 
	while ($row = mysqli_fetch_array($qresult)){		
		$xmlRow .= '
			<tr>
				<td>'.$row["menusubsub"].'</td>    
				<td>  
					<a href="javascript:eliminar_permiso_subsubmenu('.$row["id_permiso"].')" class="btn btn-danger" data-toggle="tooltip" title="eliminar"><i class="fa fa-pencil"></i> ELIMINAR PERMISOS SUBMENU </a>
				</td> 
			</tr>  
		'; 
	}	  
	 
	/* obtiene el menu */
	$query2 = "SELECT menu.menu, menusub.menusub 
		FROM menusub
		INNER JOIN menu ON (menu.id_menu = menusub.id_menu)
		WHERE menusub.id_menusub = ".$id_menusub;
	$menu	 = GetValueSQL($query2,"menu")." / ".GetValueSQL($query2,"menusub");
	
	
	/* obtiene el almacen */
	$query2 = "SELECT nombre FROM almacen WHERE id_almacen = ".$id_almacen;
	$bodega = GetValueSQL($query2,"nombre");
	/* obtiene el tipo user */
	$query2 = "SELECT tipo_usuario FROM tipo_usuario WHERE id_tipo_usuario = ".$id_tipo_usuario;
	$tipo_usuario = GetValueSQL($query2,"tipo_usuario");
	
	$result = array(   
		'table_permiso_submenu' => $xmlRow,  
		'bodega' 				=> $bodega, 
		'tipo_usuario' 			=> $tipo_usuario,  
		'menu' 					=> $menu,
		'acciones' 				=> $acciones, 
		'result' 				=> $resultStatus, 
		'result_text' 			=> $resultText
	);		
	XML_Envelope($result);     
	exit;	
}
 
