		$fecha_fin 			= formato_fecha_sql($fecha_fin);	
		$where = " WHERE traspaso_inventario.fecha_enviado BETWEEN '".$fecha_inicio."' AND '".$fecha_fin."' ";
		$limite =  "";
	}	
 	
	if($sucursal_origen > 0){ 
		$where .= " AND traspaso_inventario.id_sucursal_origen = ".$sucursal_origen;
	}
	if($sucursal_destino > 0){
		$where .= " AND traspaso_inventario.id_sucursal_destino = ".$sucursal_destino;
	}
		
