		$where_almacen = "";
	}			 
	$query = "SELECT traspaso_inventario.id_traspaso, traspaso_inventario.id_salida, traspaso_inventario.fecha_enviado, traspaso_inventario.fecha_recibido, 
					traspaso_inventario.id_sucursal_destino, traspaso_inventario.id_sucursal_origen, 
