					almacen1.nombre AS almacen_origen, almacen2.nombre AS almacen_destino, usuario.nombre AS username
					FROM traspaso_inventario  
					INNER JOIN salida_almacen_rapida ON (salida_almacen_rapida.id_salida = traspaso_inventario.id_salida) 
					INNER JOIN usuario ON (usuario.id_usuario = traspaso_inventario.id_usuario_kardex) 
					INNER JOIN almacen AS almacen1 ON (almacen1.id_almacen = traspaso_inventario.id_sucursal_origen)
					INNER JOIN almacen AS almacen2 ON (almacen2.id_almacen = traspaso_inventario.id_sucursal_destino)
					".$where.$where_almacen." ORDER BY traspaso_inventario.fecha_enviado DESC ".$limite;
	$qresult = DatasetSQL($query); 
	while ($row = mysqli_fetch_array($qresult)){		
		//$query2 = "SELECT COUNT(id_inventario) AS existe, SUM(cantidad) AS sumatoria FROM inventario_tmp WHERE id_entrada = ".$row["id_entrada"];			
		$query2 = "SELECT COUNT(id_salida_inv) AS existe, SUM(cantidad) AS sumatoria FROM salida_almacen_rapida_inv WHERE id_salida = ".$row["id_salida"];	
