				$fecha_recibido = $row["fecha_recibido"]; 
				$btn_recibir 	= "";
				$btn_cancelar 	= ""; 
			}else{ 
				$fecha_recibido = "Pendiente de recibir";
				
				if($row["id_sucursal_destino"] == $_SESSION['id_almacen']){
					$btn_recibir = '<a href="javascript:recibir_traspaso('.$row["id_traspaso"].')" class="btn btn-success" data-toggle="tooltip" title="Recibir"><i class="fa fa-pencil"></i> ACEPTAR TRASPASO </a>';
				}else{
					$btn_recibir = "";
				}
				if($tipo_de_usuario === $tipo_usuario_sistemas){
					$btn_cancelar = '<a href="javascript:cancelar_traspaso('.$row["id_traspaso"].')" class="btn btn-danger" data-toggle="tooltip" title="Recibir"><i class="fa fa-pencil"></i> CANCELAR TRASPASO </a>';
				}else{
					$btn_cancelar = "";
					/* temporalmente TODOS tienen permiso al botón CANCELAR*/
					/* siempre y cuando el transpaso NO haya sido aceptado y se encuentre en la sucursal ORIGEN*/
					if($row["id_sucursal_origen"] == $_SESSION['id_almacen']){
						$btn_cancelar = '<a href="javascript:cancelar_traspaso('.$row["id_traspaso"].')" class="btn btn-danger" data-toggle="tooltip" title="Recibir"><i class="fa fa-pencil"></i> CANCELAR TRASPASO </a>';
					}
				}	
			}
			
			if($row['codigo_salida'] == ""){
				$codigo_traspaso = $row['id_traspaso'];
			}else{
				$codigo_traspaso = $row['codigo_salida'];
			}
			
			$xmlRow .= '
				<tr> 
					<td>'.$codigo_traspaso.'</td> 
					<td>'.$row["fecha_enviado"].'</td>
					<td>'.$fecha_recibido.'</td> 
					<td>'.$row["almacen_origen"].'</td> 
					<td>'.$row["almacen_destino"].'</td> 
					<td>'.$sumatoria.'</td> 
					<td>'.$row["motivos"].'</td> 
					<td>'.$row["kardex"].'</td> 
					<td>'.$row["username"].'</td> 
					<td> 
					';	 
					if($acciones == "si"){ 
						$xmlRow .= '   
							<a target="_blank" href="ver_traspaso_detalle.php?id_salida='.$row["id_salida"].'" class="btn btn-primary" data-toggle="tooltip" title="Ver Detalles"><i class="fa fa-pencil"></i> Ver detalles </a>
							<a href="javascript:imprimir_pdf_traspaso_almacen('.$row["id_salida"].')" class="btn btn-warning" data-toggle="tooltip" title="Imprimir PDF"><i class="fa fa-pencil"></i> IMPRIMIR PDF</a>
							'.$btn_recibir." ".$btn_cancelar;
					}	
					$xmlRow .= '
					</td>
				</tr>  
			';
		} 
	}	
	
	$result = array( 
		'table_traspasos_almacen' 	=> $xmlRow,  
		'acciones' 					=> $acciones, 
		'result' 					=> $resultStatus, 
		'result_text' 				=> $resultText
	);		
	XML_Envelope($result);     
	exit;	
}
  
 
