function funcion_buscar_check($datos){
	
	$info = explode("_", $datos); 
	 
	$id_cirugia = $info[0];
	$campo = $info[1];
	$valor = $info[2];
	
	$selected = "";
	
	$query = "SELECT COUNT(id_check) AS existe FROM cirugia_check_manual WHERE id_cirugia = ".$id_cirugia." AND ".$campo." = '".$valor."'";
	$existe = GetValueSQL($query,"existe");
	
	if($existe > 0){
		//echo $query."<br>";
		$selected = "selected";
	}else{
		$selected = "";
	}
	
	return $selected;
	
}
