	$faicono 		= "";
	$ubicacion 		= "";
	$prestado 		= 0;
	$esadmin 		= 0;
		
	$query_tu = "SELECT tipo_usuario FROM tipo_usuario WHERE id_tipo_usuario = ".$_SESSION['id_tipo_usuario'];
	$tipo_de_usuario = GetValueSQL($query_tu,"tipo_usuario");
	if($tipo_de_usuario === $tipo_usuario_sistemas OR $tipo_de_usuario === $tipo_usuario_administrador 
		OR $tipo_de_usuario === $tipo_usuario_gerente){	
			$acciones 		= "si";
			$esadmin = 1;
	}	
	/* usuario logitica NO puede editar SET */
	
	$query = "SELECT almacen_set.id_set, almacen_set.nombre, almacen_set.codigo, almacen_set.cajas, almacen_set.kardex, almacen_set.estatus, 
				estatus_set.nombre AS estatusset, usuario.nombre AS username, set_categoria.nombre AS categoria, set_subcategoria.nombre AS subcategoria,
				almacen.nombre AS almacen_name 
				FROM almacen_set
				INNER JOIN set_categoria ON (set_categoria.id_set_categoria = almacen_set.id_set_categoria) 
				INNER JOIN set_subcategoria ON (set_subcategoria.id_set_subcategoria = almacen_set.id_set_subcategoria)
				INNER JOIN estatus_set ON (estatus_set.id_estatus_set = almacen_set.estatus)
				INNER JOIN usuario ON (usuario.id_usuario = almacen_set.id_usuario_kardex)
				INNER JOIN almacen ON (almacen.id_almacen = almacen_set.id_almacen) 
				WHERE almacen_set.id_almacen = ".$_SESSION['id_almacen']."
				ORDER BY almacen_set.nombre
			";

	$qresult = DatasetSQL($query); 
	while ($row = mysqli_fetch_array($qresult)){	
		
		if($tipo_de_usuario === $tipo_usuario_logistica OR $tipo_de_usuario === $tipo_usuario_mesa_de_control ){ 
			$btn_editar_set = '<a href="transferir_set.php?id_set='.$row["id_set"].'" class="btn btn-warning" data-toggle="tooltip" title="Transferir entre Activos o Entre Surucsales  "><i class="fa fa-pencil"></i> Transferir Contenido </a>';
			//$btn_editar_set = '';
		}else{ 
			$btn_editar_set = '
				<a href="prestar_set.php?id_set='.$row["id_set"].'" class="btn btn-primary" data-toggle="tooltip" title="Prestar Activo a otra Sucursal "><i class="fa fa-pencil"></i> Prestar Set </a>
				<a href="transferir_set.php?id_set='.$row["id_set"].'" class="btn btn-info" data-toggle="tooltip" title="Transferir  entre Activos o Entre Surucsales"><i class="fa fa-pencil"></i> Transferir Contenido </a>
				<a href="editar_set.php?id_set='.$row["id_set"].'" class="btn btn-warning" data-toggle="tooltip" title="Editar o Resurtir"><i class="fa fa-pencil"></i> Editar / Resurtir</a>
				<a href="javascript:imprimir_qr_activos(1,'.$row["id_set"].')" class="btn btn-success" data-toggle="tooltip" title="Eliminar "><i class="fa fa-pencil"></i> IMPRIMIR ETIQUETAS QR</a>
				';
		}
	
		
		if($row["estatusset"] == $estatus_en_cirugia AND $esadmin == 0){
			$btn_editar_set = "Activo fuera de bodega. Si necesita modificar solicite apoyo a Administrador";
			$acciones = "no";
		}
			
			
		if($row["estatusset"] == $estatus_en_cirugia){
			$query_cir = "SELECT COUNT(cirugia_minialmacen.id_cirugia) AS existe, cirugia.codigo FROM cirugia_minialmacen
				INNER JOIN cirugia ON (cirugia.id_cirugia = cirugia_minialmacen.id_cirugia)
				WHERE  cirugia_minialmacen.id_minialmacen = ".$row["id_set"]. "
				ORDER BY cirugia_minialmacen.kardex DESC";
				$existe = GetValueSQL($query_cir,"existe");
				if($existe > 0){
					$ubicacion = GetValueSQL($query_cir,"codigo");
					
				}else{
					$ubicacion = "Cirugía no identificada";
				}
		}else{			
			$query_cir_x = "SELECT COUNT(id_prestamo) AS existe, id_sucursal_prestamo, almacen.nombre 
				FROM prestamo_set 
				INNER JOIN almacen ON (almacen.id_almacen = prestamo_set.id_sucursal_prestamo)
				WHERE prestamo_set.id_set = ".$row["id_set"]." AND prestamo_set.fecha_devolucion = '0000-00-00'";
			$existe_x = GetValueSQL($query_cir_x,"existe");
			if($existe_x > 0){ // existe un prestamo
				$ubicacion = GetValueSQL($query_cir_x,"nombre");
				$prestado = 1;
			}else{
				$query_cir = "SELECT almacen.nombre FROM almacen_set
					INNER JOIN almacen ON (almacen.id_almacen = almacen_set.id_almacen)
					WHERE almacen_set.id_set = ".$row["id_set"];
				$ubicacion = GetValueSQL($query_cir,"nombre"); 
				$prestado = 0;
			}			
		}
	
		if($tipo_de_usuario === $tipo_usuario_vidente){	
			$btn_editar_set = ''; 
		}	
		
		if($prestado == 1){
			$btn_editar_set = '<a href="prestar_set.php?id_set='.$row["id_set"].'" class="btn btn-primary" data-toggle="tooltip" title="Prestar Activo a otra Sucursal "><i class="fa fa-pencil"></i> Prestar Set </a>'; 
		}
		
		$xmlRow .= '
			<tr>
				<td> '.$btn_editar_set;	
				//  //<a href="master_set.php?id_set='.$row["id_set"].'" class="btn btn-info" data-toggle="tooltip" title="Master "><i class="fa fa-pencil"></i> Lista Maestra </a>
							
					if($acciones == "si"){
						$xmlRow .= '	
							
							<a href="javascript:eliminar_set('.$row["id_set"].')" class="btn btn-danger" data-toggle="tooltip" title="Eliminar "><i class="fa fa-pencil"></i> Eliminar</a>
						';
					}
					$xmlRow .= ' 
				</td>
				<td>'.$row["almacen_name"].'</td> 
				<td>'.$row["categoria"].'</td>
				<td>'.$row["subcategoria"].'</td>
				<td>'.$row["nombre"].'</td>
				<td>'.$row["codigo"].'</td>
				<td>'.$row["cajas"].'</td>
				<td>'.$row["estatusset"].' / '.$ubicacion.'</td>
				<td>'.$row["kardex"].'</td>
				<td>'.$row["username"].'</td>
				<td> '.$btn_editar_set;	
					if($acciones == "si"){
						$xmlRow .= '							
							<a href="javascript:eliminar_set('.$row["id_set"].')" class="btn btn-danger" data-toggle="tooltip" title="Eliminar Fabricantes"><i class="fa fa-pencil"></i> Eliminar</a>
						';
					}
					$xmlRow .= '
				</td>
			</tr> 
		';
	}	
	
	
	/* AHORA BUSCAMOS SETS PRESTADOS */
	$query = "SELECT id_set FROM prestamo_set WHERE id_sucursal_prestamo = ".$_SESSION['id_almacen']." AND fecha_devolucion = '0000-00-00'";
	$qresult = DatasetSQL($query); 
	while ($row = mysqli_fetch_array($qresult)){	
		$query_p = "SELECT almacen_set.id_set, almacen_set.nombre, almacen_set.codigo, almacen_set.cajas, almacen_set.kardex,
				estatus_set.nombre AS estatusset, usuario.nombre AS username, set_categoria.nombre AS categoria, set_subcategoria.nombre AS subcategoria,
				almacen.nombre AS almacen_name 
				FROM almacen_set
				INNER JOIN set_categoria ON (set_categoria.id_set_categoria = almacen_set.id_set_categoria) 
				INNER JOIN set_subcategoria ON (set_subcategoria.id_set_subcategoria = almacen_set.id_set_subcategoria)
				INNER JOIN estatus_set ON (estatus_set.id_estatus_set = almacen_set.estatus)
				INNER JOIN usuario ON (usuario.id_usuario = almacen_set.id_usuario_kardex)
				INNER JOIN almacen ON (almacen.id_almacen = almacen_set.id_almacen) 
