		$mail->SMTPAuth = true; 
		$mail->SMTPSecure = "ssl";
		$mail->Username = "notificaciones@creaccionesweb.com";
		$mail->Password = "creaccionesweb";
		$mail->SetFrom( 'notificaciones@creaccionesweb.com' , 'creaccionesweb' );	
		$mail->AddAddress($email , $nombre );	
		$mail->Subject = utf8_encode($subject);
		$message = isset($message) ? "$message<br><br>" : '';
		//$referrer = $_SERVER['HTTP_REFERER'] ? '<br><br><br>Has recibido este correo desde: ' . $_SERVER['HTTP_REFERER'] : '';
		$referrer = '<br><br><br>';
		$body = $nombre.utf8_encode($message).$referrer;
		$mail->IsHTML(true);
		$mail->MsgHTML( $body );
		//$sendEmail = $mail->Send();		
		$mail->ClearAllRecipients();	
	}
 
	if($telefono == ""){
		$enviar_whatsapp = "";
	}else{
		$telefono = str_replace(" ","",$telefono);
		$enviar_whatsapp = "https://api.whatsapp.com/send?phone=521".$telefono."&text=Estimado ".$nombre.". Su cirugia con clave ".$codigo." ha quedado exitosamente programada";
