		//	$logo 			= GetValueSQL($query,"logo");  
		//	$codigo_qr 		= GetValueSQL($query,"codigo_qr");  
		//	$id_activo 		= GetValueSQL($query,"id_activo");  
	
		/* crear codigo QR */
		$logo = "";
		$textodelqr = "CX".$id_cirugia;
		 
		/* elimina acentos*/ 
		$fechatoday = strtotime(date("Y-m-d H:i:s")); 
		$filename = $PNG_WEB_DIR.'/qrcode_cx_'.$fechatoday.'.png'; 
		$filename_save = 'codigos_qr/qrcode_cx_'.$fechatoday.'.png'; 			 
		$writer = new PngWriter();
		// Create QR code
		$qrCode = QrCode::create($textodelqr)
			->setEncoding(new Encoding('UTF-8'))
			->setErrorCorrectionLevel(new ErrorCorrectionLevelLow())
			->setSize(300)
			->setMargin(10)
			->setRoundBlockSizeMode(new RoundBlockSizeModeMargin())
			->setForegroundColor(new Color(0, 0, 0))
			->setBackgroundColor(new Color(255, 255, 255));		
		// Create generic logo
