		$result->saveToFile($filename_save);		
		$dataUri = $result->getDataUri();
		
		$queryupqr = "UPDATE cirugia SET codigo_qr = '".$filename_save."' WHERE id_cirugia = ".$id_cirugia;
		ExecuteSQL($queryupqr);
	
