/* productos set*/
if (Requesting("action")=="transferir_producto_set"){  
	$id_set_destino 	= Requesting("set_destino"); 
	$id_producto_set 	= Requesting("id_producto_set"); 
	
	$resultStatus 		= "ok"; 
	$resultText 		= "El registro ha sido transferido";	

	$query1 = "SELECT id_set, id_inventario, cantidad FROM producto_set WHERE id_producto_set = ".$id_producto_set;
	$id_set 				= GetValueSQL($query1,"id_set");
	$id_inventario 			= GetValueSQL($query1,"id_inventario");
	$cantidad_actual_origen = GetValueSQL($query1,"cantidad"); 
	$cantidad_nueva_origen 	= ($cantidad_actual_origen) - 1;

	$query2 = "SELECT COUNT(id_producto_set) AS existe, id_producto_set, cantidad FROM producto_set 
		WHERE id_set = ".$id_set_destino." AND id_inventario = ".$id_inventario;
	$existe = GetValueSQL($query2,"existe");
	if($existe > 0){
		$id_producto_set_destino = GetValueSQL($query2,"id_producto_set");
		$cantidad_actual_destino = GetValueSQL($query2,"cantidad");
		$cantidad_nueva_destino = ($cantidad_actual_destino) + 1;
		
		$query3 = "UPDATE producto_set SET cantidad = ".$cantidad_nueva_destino.", kardex = NOW(), id_usuario_kardex = ".$_SESSION['id_sesion']." WHERE id_producto_set = ".$id_producto_set_destino;
		ExecuteSQL($query3); 
	}else{
		$query3 = "INSERT INTO producto_set (id_set, id_inventario, cantidad, kardex, id_usuario_kardex) 
		VALUES(".$id_set_destino.", ".$id_inventario.", 1, NOW(), ".$_SESSION['id_sesion'].")";
		ExecuteSQL($query3); 		
	}

	if($cantidad_nueva_origen <= 0){
		$query4 = "DELETE FROM producto_set WHERE id_producto_set = ".$id_producto_set;
	}else{
		$query4 = "UPDATE producto_set SET cantidad = ".$cantidad_nueva_origen." WHERE id_producto_set = ".$id_producto_set;
	}
	ExecuteSQL($query4); 

	
	$result = array(
		'result' 		=> $resultStatus, 
		'result_text' 	=> $resultText
	);	 
	XML_Envelope($result);     
	exit;	
	
}

