if (Requesting("action")=="eliminar_set"){  
	$id_set 		= Requesting("id_set"); 
	$resultStatus 	= "ok"; 
	$resultText 	= "Registro eliminado correctamente";		
	
	/* primero verificamos el contenido del SET, para devolver a inventario*/
	$query = "SELECT id_inventario, cantidad FROM producto_set WHERE id_set = ".$id_set;
	$qresult = DatasetSQL($query);
	while ($row = mysqli_fetch_array($qresult)){
		$query2 = "SELECT cantidad FROM inventario WHERE id_inventario = ".$row['id_inventario'];
		$cantidad_actual = GetValueSQL($query2,"cantidad");
		$nueva_cantidad = ($cantidad_actual) + ($row['cantidad']);
		
		$query3 = "UPDATE inventario SET cantidad = ".$nueva_cantidad." WHERE id_inventario = ".$row['id_inventario'];
		ExecuteSQL($query3); 
		
	} 
	
	$query4 = "DELETE FROM producto_set WHERE id_set = ".$id_set;
	ExecuteSQL($query4); 
	
	$query5 = "DELETE FROM activo_set WHERE id_set = ".$id_set;
	ExecuteSQL($query5); 
	
	$result = array(
		'result' 		=> $resultStatus, 
		'result_text' 	=> $resultText
	);	 
	XML_Envelope($result);     
	exit;	
	
}

