	}else{ 
		if($existe2 > 0){
			$resultStatus 	= "Error"; 
			$resultText 	= "No se puede eliminar por que existe un técnico con este usuario.";		
		}else{
			$query = "DELETE FROM usuario WHERE id_usuario = ".$id_usuario;
			ExecuteSQL($query); 
		}
	}
	
	 	
	$result = array(
		'result' 		=> $resultStatus, 
