/* llena el listado de instrumentales que se van a registrar como escaneo para consumos */
if (Requesting("action")=="llenar_div_instrumentales_cirugia"){ 	 

	$id_cirugia = Requesting("id_cirugia");
	$id_instrumental = Requesting("id_instrumental");
	
	$resultStatus 	= "ok";
	$resultText 	= "Correcto.";	 
	$xmlRow = ""; 
	$numero = "1"; 
	 
	/* ahora instrumental*/
	$query = "SELECT cirugia_instrumental.id_cirugia_instrumental, cirugia_instrumental.id_instrumental, instrumental.nombre FROM cirugia_instrumental 
				INNER JOIN instrumental ON (instrumental.id_instrumental = cirugia_instrumental.id_instrumental)
				WHERE id_cirugia = ".$id_cirugia; 
	$qresult = DatasetSQL($query);
	while ($row = mysqli_fetch_array($qresult)){
		
		
		
		$xmlRow .= '		
			<div class="col-md-12 mb-3">
				<div class="form-group">
					<label class="control-label" style="font-size:24px; font-weight:900">'.$row['nombre'].'</label>';
					 
					 
		$query2 = "SELECT id_producto_instrumental, id_inventario, cantidad FROM producto_instrumental WHERE id_instrumental = ".$row['id_instrumental'];
		$qresult2 = DatasetSQL($query2);
		while ($row2 = mysqli_fetch_array($qresult2)){
			$query3 = "SELECT COUNT(id_inventario) AS exist_inv, inventario.id_inventario, producto.nombre, producto.referencia 
				FROM inventario 
				INNER JOIN producto ON (producto.id_producto = inventario.id_producto) WHERE id_inventario = ".$row2['id_inventario'];
			$exist_inv = GetValueSQL($query3,"exist_inv");
			
			if($exist_inv > 0){
				$id_inventario = GetValueSQL($query3,"id_inventario");
				$nombre = GetValueSQL($query3,"nombre");
				$referencia = GetValueSQL($query3,"referencia");
			}else{ 
				$id_inventario = 0;
				$nombre = "NA";
				$referencia = "NA";
			}
			
			$numero++;
			if ($numero%2==0){
				$color_row = "#FFF";
			}else{
				$color_row = "#EEE";
			} 

			
			
			$reference = str_replace("-", ".", $referencia);
			 
			$xmlRow .= '				
				
				<div class="form-group row" style="padding:10px 0px; background-color:'.$color_row.'">
					<label for="staticEmail" class="col-6 col-form-label">'.$reference.' - '.$nombre.'</label>
					<div class="col-6 div_consumos">
						<input class="form-control" type="number" name="cantidad_ins" value="'.$row2['cantidad'].'"> 			
						<input class="form-control" type="hidden" name="consumo_ins" value="'.$row2['id_producto_instrumental'].'"> 			
					</div>
				<div>
  
  
			';
				
		$xmlRow .= '</div></div>';
		} 
		
	}
		
	$result = array(    
		'instrumentales' 		=> $xmlRow,    
		'result' 			=> $resultStatus, 
		'result_text' 		=> $resultText
	);		 
	XML_Envelope($result);  
	exit;		 
}


