if (Requesting("action")=="llenar_div_nuevo_cirugia_relacion_readonly"){ 	
	
	$id_cirugia = Requesting("id_cirugia"); 
	
	$resultStatus 	= "ok";
	$resultText 	= "Correcto.";	 
	$xmlRow = "";  
	$nombre_equipo_lista = ""; 
	 

	$query = "SELECT cirugia.minialmacen, cirugia.equipo_poder, cirugia.adicionales, cirugia.consumibles 
			FROM cirugia 
			WHERE id_cirugia = ".$id_cirugia;
	$minialmacen 	= GetValueSQL($query,"minialmacen");
	$equipo_poder 	= GetValueSQL($query,"equipo_poder");
	$adicionales 	= GetValueSQL($query,"adicionales");
	$consumibles 	= GetValueSQL($query,"consumibles");
	
	/* buscar equipos de poder*/
	$porciones = explode(",", $equipo_poder);			
	foreach ($porciones as &$valor) {
		if($valor != ""){
			$query_ep = "SELECT nombre FROM equipo_poder_categoria WHERE id_ep_categoria = ".$valor;
			$nombre_equipo = GetValueSQL($query_ep,"nombre");
			$nombre_equipo_lista .= $nombre_equipo.",<br>";
		}
	}
	$nombre_equipo_lista = rtrim($nombre_equipo_lista, ",<br>");
		
	$nombre_consumibles_lista = "";
	if($consumibles != ""){ 
		$porciones = explode(",", $consumibles);			
		foreach ($porciones as &$valor) {
			if($valor != ""){
				$query_ad = "SELECT nombre FROM consumible_categoria WHERE id_consu_categoria = ".$valor;
				$nombre_consumibles = GetValueSQL($query_ad,"nombre");
				$nombre_consumibles_lista .= $nombre_consumibles.", ";
			}
		}
		$nombre_consumibles_lista = rtrim($nombre_consumibles_lista, ", ");
	}		
	/* buscar adicionales*/
	$nombre_adicionales_lista = "";
	if($adicionales != ""){ 
		$porciones = explode(",", $adicionales);			
		foreach ($porciones as &$valor) {
			if($valor != ""){
				$query_ad = "SELECT nombre FROM instrumental_categoria WHERE id_instru_categoria = ".$valor;
				$nombre_adicionales = GetValueSQL($query_ad,"nombre");
				$nombre_adicionales_lista .= $nombre_adicionales.", ";
			}
		}
		$nombre_adicionales_lista = rtrim($nombre_adicionales_lista, ", ");
	}	
		
	/* buscar material / minialmacen*/
	$minialmacen_lista = "";
	if($minialmacen != ""){
		$porciones = explode(",", $minialmacen);			
		foreach ($porciones as &$valor) { 
			if($valor != ""){
				$porciones_sub = explode("/", $valor);
				$set_categoria = $porciones_sub[0];
				$set_subcategoria = $porciones_sub[1];
				
				$query_sc = "SELECT nombre FROM set_categoria WHERE id_set_categoria = ".$set_categoria;
				$categoria_nombre = GetValueSQL($query_sc,"nombre");
				$query_ss = "SELECT nombre FROM set_subcategoria WHERE id_set_subcategoria = ".$set_subcategoria;
				$subcategoria_nombre = GetValueSQL($query_ss,"nombre");
				
				$minialmacen_lista .= $subcategoria_nombre.", ";
				
			}
		}
		$minialmacen_lista = rtrim($minialmacen_lista, ", ");
	}
	
	$xmlRow = "MATERIAL SOLICITADO: <br><br><br>
		".$minialmacen_lista."<br>
		".$nombre_consumibles_lista." <br>
		".$nombre_equipo_lista."<br>
		".$nombre_adicionales_lista;
	
	
	/*ahora busco, si la cirugia ya se surtió con qué se surtió*/
	
	
	
	
	$result = array(    
		'nuevo_cirugia_relacion_readonly' 		=> $xmlRow,    
		'result' 			=> $resultStatus, 
		'result_text' 		=> $resultText
	);		 
	XML_Envelope($result);  
	exit;		 
}

