if (Requesting("action")=="llenar_div_reportar_consumos"){    
	
	$id_cirugia = Requesting("id_cirugia");
	
	$resultStatus 	= "ok";
	$resultText 	= "Correcto.";	 
	$xmlRow = ""; 
	$numero = "0"; 

	$query = "SELECT cirugia_minialmacen.id_minialmacen, almacen_set.nombre FROM cirugia_minialmacen 
				INNER JOIN almacen_set ON (almacen_set.id_set = cirugia_minialmacen.id_minialmacen)
				WHERE id_cirugia = ".$id_cirugia;
	$qresult = DatasetSQL($query);
	while ($row = mysqli_fetch_array($qresult)){
		
		
		
		$xmlRow .= '		
			<div class="col-md-12 mb-3">
				<div class="form-group">
					<label class="control-label" style="font-size:24px; font-weight:900">'.$row['nombre'].'</label>';
					
					
		$query2 = "SELECT id_producto_set, id_inventario, cantidad FROM producto_set WHERE id_set = ".$row['id_minialmacen'];
		$qresult2 = DatasetSQL($query2);
		while ($row2 = mysqli_fetch_array($qresult2)){
			$query3 = "SELECT inventario.id_inventario, producto.nombre, producto.referencia FROM inventario INNER JOIN producto ON (producto.id_producto = inventario.id_producto) WHERE id_inventario = ".$row2['id_inventario'];
			$id_inventario = GetValueSQL($query3,"id_inventario");
			$nombre = GetValueSQL($query3,"nombre");
			$referencia = GetValueSQL($query3,"referencia");
			/*
			$xmlRow .= ' 		
						
				<div class="form-check"> 
					<input class="form-check-input" type="checkbox" name="consumo" value="'.$id_inventario.'">
					<label class="form-check-label">'.$nombre.'</label>
				</div>	';
			*/
			$numero++;
			if ($numero%2==0){
				$color_row = "#FFF";
			}else{
				$color_row = "#EEE";
			} 


			/* busca consumos actuales */ 
			
			$query4 = "SELECT COUNT(id_cirugia_consumo) AS existe, cantidad FROM cirugia_consumo WHERE id_cirugia = ".$id_cirugia." AND id_producto_set = ".$row2['id_producto_set'];
			$existe = GetValueSQL($query4, "existe");
			if($existe > 0){
				$cantidad_actual = GetValueSQL($query4, "cantidad");
			}else{
				$cantidad_actual = 0;
			}
			
			$reference = str_replace("-", ".", $referencia);
			
			$xmlRow .= '				
				<div class="form-group row" style="padding:10px 0px; background-color:'.$color_row.'">
					<label for="staticEmail" class="col-6 col-form-label">'.$reference.' - '.$nombre.'</label>
					<div class="col-6 div_consumos">
						<input class="form-control" type="number" name="cantidad" value="'.$cantidad_actual.'"> 			
						<input class="form-control" type="hidden" name="consumo" value="'.$row2['id_producto_set'].'"> 			
					</div>
				<div>';
				
		} 
		
		$xmlRow .= '</div></div>';
	}
	
	$result = array(  
		'reportar_consumos' => $xmlRow,    
		'result' 			=> $resultStatus, 
		'result_text' 		=> $resultText
	);		 
	XML_Envelope($result);  
	exit;		 
} 
 
  
