function formato_fecha_lectura($fecha_sql){  
	//2020-06-20 16:42:04
	$mes = "";
	$array_date = explode("-",$fecha_sql); /* Separa date */
	switch($array_date[1]){
		case "01": $mes = "Enero"; break;
		case "02": $mes = "Febrero"; break;
		case "03": $mes = "Marzo"; break;
		case "04": $mes = "Abril"; break; 
		case "05": $mes = "Mayo"; break;
		case "06": $mes = "Junio"; break;
		case "07": $mes = "Julio"; break;
		case "08": $mes = "Agosto"; break;
		case "09": $mes = "Septiembre"; break;
		case "10": $mes = "Octubre"; break;
		case "11": $mes = "Noviembre"; break;
		case "12": $mes = "Diciembre"; break;
	}
	$fecha_lectura = $array_date[2] ." ". $mes. " " .$array_date[0];
	return $fecha_lectura;
} 
function formato_fecha_codigo($fecha_codigo){  
	//2020-06-20 16:42:04
	$anio = substr($fecha_codigo,0,2);
	$mes = substr($fecha_codigo,2,2);
	$dia = substr($fecha_codigo,4,2);

	$fecha_lectura = "20".$anio."-".$mes."-".$dia;
	return $fecha_lectura;
} 
function formato_fecha_sql($fecha){  
	// recibo 11 julio 2022   // regreso 2022-07-11
	$array_date = explode(" ",$fecha); /* Separa date */
	switch($array_date[1]){
		case "Enero": $mes = "01"; break;
		case "Febrero": $mes = "02"; break;
		case "Marzo": $mes = "03"; break;
		case "Abril": $mes = "04"; break; 
		case "Mayo": $mes = "05"; break;
		case "Junio": $mes = "06"; break;
		case "Julio": $mes = "07"; break; 
		case "Agosto": $mes = "08"; break;
		case "Septiembre": $mes = "09"; break;
		case "Octubre": $mes = "10"; break;
		case "Noviembre": $mes = "11"; break;
		case "Diciembre": $mes = "12"; break;
	} 

	if(strlen($array_date[0]) == 1){
		$dia = "0".$array_date[0];
	}else{
		$dia = $array_date[0];
	} 
	
	$fecha_sql = $array_date[2]."-".$mes."-".$dia;
	return $fecha_sql;
}
 
 
function segundos_a_time($segundos) {
    $minutos = $segundos / 60;
    $horas = floor($minutos / 60);
    $minutos2 = $minutos % 60;
    $segundos_2 = $segundos % 60 % 60 % 60;
    if ($minutos2 < 10) 
        $minutos2 = '0'.$minutos2;
    
    if ($segundos_2 < 10) 
        $segundos_2 = '0'.$segundos_2;
    
    if ($segundos < 60) { /* segundos */
        $resultado = round($segundos).' Segundos';
    }
    elseif($segundos > 60 && $segundos < 3600) { /* minutos */
        $resultado = $minutos2
            .':'
            .$segundos_2
            .' Minutos';
    } else { /* horas */
        $resultado = $horas . ':' . $minutos2 . ':' . $segundos_2 . ' Horas';
    }
    return $resultado;
}

	
